      const prompt = `SEARCH COMMAND: 
      ১. "${train.name} (${train.id})" ট্রেনের বর্তমান অবস্থান কি?
      ২. "বাংলাদেশ রেলওয়ে ফ্যান গ্রুপ" এবং "রাজবাড়ী ট্রেন ক্লাব" ফেসবুক পেজ বা গ্রুপে গত ১ ঘণ্টার কোনো পোস্ট আছে কিনা দেখুন।
      ৩. ট্রেনটির রুট: ${train.detailedRoute}।
      ৪. বর্তমান সময়: ${currentTime.toLocaleTimeString('bn-BD')}।

      তথ্যসূত্রসহ বিস্তারিত উত্তর দিন। যদি সুনির্দিষ্ট লোকেশন পান, তবে নিচের JSON ফরম্যাটে দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.9,
        "reason": "লোকেশন রিপোর্ট এখানে",
        "likelyCurrentStation": "স্টেশনের নাম"
      }`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }]
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      const start = text.indexOf('{');
      const end = text.lastIndexOf('}');
      if (start !== -1 && end !== -1) {
        try {
          const jsonPart = JSON.parse(text.substring(start, end + 1));
          setAiInference({ ...jsonPart, isAI: true, sources, rawText: text });
        } catch(e) {
          setAiInference({ delayMinutes: 0, confidence: 0.6, reason: text, isAI: true, sources, rawText: text });
        }
      } else {
        setAiInference({ delayMinutes: 0, confidence: 0.6, reason: text, isAI: true, sources, rawText: text });
      }
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভারে সমস্যা হয়েছে। পুনরায় চেষ্টা করুন।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    if (inference.isAI && inference.likelyCurrentStation && inference.confidence > 0.4) {
      const foundIdx = stations.findIndex(s => s.toLowerCase().includes(inference.likelyCurrentStation!.toLowerCase().trim()));
      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ রিপোর্ট: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '৮': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const [t, ampm] = normTime.split(' ');
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;
    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায়', stationIndex: 0 };
    const idx = Math.min(Math.max(0, Math.floor(diff / 20)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };

