import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference, Type } from '../types';
