interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ ইঞ্জিন ব্যবহার করে ট্রেনের সর্বশেষ অবস্থান অনুসন্ধান করা হচ্ছে...', isAI: true, sources: [], rawText: '' });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name} (${train.id})" ট্রেনের বর্তমান অবস্থান কি?

      নির্দেশনা:
      ১. গুগল সার্চ ব্যবহার করে গত ১ ঘণ্টার সোশ্যাল মিডিয়া পোস্ট বা লাইভ ট্র্যাকার ডাটা চেক করুন।
      ২. আপনার উত্তরের শেষে এই ফরম্যাটে একটি JSON ব্লক দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.9,
        "reason": "সংক্ষিপ্ত কারণ বাংলায়",
        "likelyCurrentStation": "নিকটতম স্টেশনের নাম"
      }
      ৩. যদি সুনির্দিষ্ট স্টেশন না পাওয়া যায়, তবে কেবল কারণটি বর্ণনা করুন।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }]
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      // Improved Extraction
      let parsedJson: any = null;
      const jsonMatch = text.match(/\{[\s\S]*?\}/);
      if (jsonMatch) {
        try {
          parsedJson = JSON.parse(jsonMatch[0]);
        } catch (e) {
          console.warn("JSON extraction failed, using text directly");
        }
      }

      if (parsedJson && (parsedJson.likelyCurrentStation || parsedJson.reason)) {
        setAiInference({
          delayMinutes: parsedJson.delayMinutes || 0,
          confidence: parsedJson.confidence || 0.8,
          reason: parsedJson.reason || text.split('{')[0].trim(),
          likelyCurrentStation: parsedJson.likelyCurrentStation,
          isAI: true,
          sources,
          rawText: text
        });
      } else {
        // Fallback for conversational response
        setAiInference({
          delayMinutes: 0,
          confidence: 0.5,
          reason: text.length > 300 ? text.substring(0, 300) + '...' : text,
          isAI: true,
          sources,
          rawText: text
        });
      }
    } catch (e: any) {
      console.error("Inference Error:", e);
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: 'এআই সার্ভিসের সাথে সংযোগ বিচ্ছিন্ন হয়েছে। অনুগ্রহ করে ইন্টারনেট চেক করে আবার চেষ্টা করুন।', 
        isAI: false, 
        sources: [], 
        rawText: '' 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    // Check if AI found a station
    if (inference.isAI && inference.likelyCurrentStation && inference.confidence > 0.4) {
      const normalizedQuery = inference.likelyCurrentStation.toLowerCase().trim();
      const foundIdx = stations.findIndex(s => 
        s.toLowerCase().includes(normalizedQuery) || 
        normalizedQuery.includes(s.toLowerCase())
      );

      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ রিপোর্ট অনুযায়ী অবস্থান: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    // Schedule Fallback
    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '⁸': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const [t, ampm] = normTime.split(' ');
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;

    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায় (শিডিউল)', stationIndex: 0 };
    const idx = Math.min(Math.max(0, Math.floor(diff / 25)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) {
      console.warn("Prayer API failed, keeping current data.");
    }
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      let prompt = "";
      let schema: any = null;

      if (category === 'market_price') {
        prompt = "Fetch current market prices for essential food items in Rajbari, Bangladesh. Respond in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        };
      } else if (category === 'notices') {
        prompt = "Find latest emergency notices or announcements from Rajbari district, Bangladesh. Respond in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              date: { type: Type.STRING },
              summary: { type: Type.STRING },
              priority: { type: Type.STRING }
            },
            required: ['title', 'date', 'summary', 'priority']
          }
        };
      }

      if (prompt && schema) {
        const response = await db.callAI({
          contents: [{ parts: [{ text: prompt }] }],
          responseMimeType: "application/json",
          responseSchema: schema
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Update Failed:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 animate-slide-up group shadow-sm transition-all hover:border-indigo-200">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className="text-[8px] text-slate-400 font-bold uppercase">ছুটি</p>
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
