          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group transition-all hover:bg-lime-50 dark:hover:bg-lime-950/20 shadow-sm">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl"><ShoppingBasket className="w-6 h-6" /></div>
