                - সর্বদা বাংলায় উত্তর দিন।
                - গুগল সার্চ ব্যবহার করে সর্বশেষ তথ্য দিন।`,
                tools: tools || [{ googleSearch: {} }],
                responseSchema: responseSchema,
                responseMimeType: responseMimeType,
                temperature: 0.1,
            }
        });

        console.log(`[AI] Success. Response length: ${response.text?.length || 0}`);

        res.json({
            text: response.text || "",
            groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
        });
    } catch (error) {
        console.error("[AI] Gemini API Error:", error.message);
        res.status(error.status || 500).json({ 
            error: error.message || "Gemini API call failed.",
            status: error.status 
        });
    }
});

