export const db = {
  /**
   * Gemini API কল করার জন্য ব্যাকএন্ড গেটওয়ে ব্যবহার করা হচ্ছে।
   * এর ফলে এপিআই কী ব্রাউজারে ফাঁস হওয়ার ভয় নেই।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    try {
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(params),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'এআই সার্ভিসে সংযোগ করা সম্ভব হচ্ছে না।');
      }

      return await response.json();
    } catch (error: any) {
      console.error("AI Bridge Error:", error);
      throw new Error(error.message || "সার্ভারের সাথে যোগাযোগ করতে সমস্যা হচ্ছে।");
    }
  },

  getCategory: async (category: string) => {
    const defaultData = (RAJBARI_DATA as any)[category] || [];
    try {
      const response = await fetch(`/api/db?category=${category}`);
      if (response.ok) {
        const serverData = await response.json();
        if (serverData && serverData.length > 0) return serverData;
      }
    } catch (e) {
      console.warn("Using offline data.");
    }
    return defaultData;
  }
};

import 'dotenv/config';
import express from 'express';
import cors from 'cors';
import path from 'path';
import { fileURLToPath } from 'url';
import { GoogleGenAI } from '@google/genai';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();
const port = process.env.PORT || 3001;

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'dist')));

/**
 * সিকিউর এআই এন্ডপয়েন্ট
 * এই এন্ডপয়েন্টটি ফ্রন্টএন্ড থেকে আসা রিকোয়েস্ট গ্রহণ করে এবং জেমিনি এপিআই কল করে।
 */
app.post('/api/ai', async (req, res) => {
    const { contents, systemInstruction, tools, responseSchema, responseMimeType } = req.body;

    if (!process.env.API_KEY) {
        return res.status(500).json({ error: "Server Configuration Error: API_KEY is missing." });
    }

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', // High-tier reasoning for public info extraction
            contents: contents,
            config: {
                systemInstruction: systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। 
                আপনার কাজ হলো রাজবাড়ী জেলার ট্রেন ট্র্যাকিং, ডাক্তার, হাসপাতাল এবং সাধারণ তথ্য প্রদান করা।
                - সর্বদা বাংলায় উত্তর দিন।
                - গুগল সার্চ ব্যবহার করে সর্বশেষ তথ্য দিন।`,
                tools: tools || [{ googleSearch: {} }],
                responseSchema: responseSchema,
                responseMimeType: responseMimeType,
                temperature: 0.1,
            }
        });

        res.json({
            text: response.text || "",
            groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
        });
    } catch (error) {
        console.error("Gemini API Error:", error.message);
        res.status(500).json({ error: error.message || "Gemini API call failed." });
    }
});

