           </button>
         )}
         {category === 'prayer' && (
           <button onClick={fetchLivePrayerTimes} className="p-4 bg-violet-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all">
             <RefreshCw className="w-5 h-5" />
