                    </div>
                    <p className="text-[13px] font-bold text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
                      {aiInference.reason || (isInferring ? 'ট্রেনের সর্বশেষ আপডেট সোশ্যাল মিডিয়া ও রেলওয়ে ফ্যান গ্রুপ থেকে খোঁজা হচ্ছে...' : 'কোনো তথ্য পাওয়া যায়নি।')}
                    </p>
                    {aiInference.sources && aiInference.sources.length > 0 && (
                      <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-200/50">
                        {aiInference.sources.map((chunk: any, sidx: number) => (
                          chunk.web && (
                            <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-[8px] font-black text-indigo-600 bg-white dark:bg-slate-800 px-2 py-1 rounded-md border border-indigo-100 hover:bg-indigo-50">
                              <Globe className="w-2 h-2" /> Source {sidx+1}
                            </a>
                          )
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {liveInfo && (
                  <div className="px-8 py-6 relative">
                    <div className="absolute left-[38px] top-8 bottom-8 w-1.5 bg-slate-100 dark:bg-slate-800 rounded-full"></div>
                    <div className="absolute left-[38px] top-8 w-1.5 bg-indigo-600 rounded-full transition-all duration-1000" style={{ height: `${liveInfo.progress}%` }}></div>
                    <div className="space-y-10 relative">
                      {selectedTrain.detailedRoute?.split(',').map((s, i) => (
                        <div key={i} className="flex items-center gap-8">
                          <div className={`w-6 h-6 rounded-full border-4 z-10 ${i < (liveInfo?.stationIndex || 0) ? 'bg-indigo-600 border-indigo-100' : i === (liveInfo?.stationIndex || 0) ? 'bg-white border-indigo-600 scale-125 shadow-lg' : 'bg-white border-slate-200'}`}></div>
                          <h5 className={`font-black uppercase tracking-tight ${i === (liveInfo?.stationIndex || 0) ? 'text-indigo-600 text-sm' : 'text-slate-400 text-[12px]'}`}>{s.trim()}</h5>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {isInferring && !selectedTrain && (
             <div className="bg-indigo-50 dark:bg-indigo-900/10 p-8 rounded-[2.5rem] border border-indigo-100 dark:border-indigo-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest">সর্বশেষ তথ্য খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference, Type } from '../types';
import { db } from '../db';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  // ==========================================
  // TRAIN LOGIC (ENHANCED STATION MATCHING)
  // ==========================================
  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ ইঞ্জিন ব্যবহার করে ট্রেনের সর্বশেষ অবস্থান অনুসন্ধান করা হচ্ছে...', isAI: true, sources: [], rawText: '' });

    const validStations = train.detailedRoute || "";

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। 
      রাজবাড়ী জেলার "${train.name} (${train.id})" ট্রেনটির বর্তমান লাইভ লোকেশন গুগল সার্চ করে বের করুন।

      ট্রেনটির সম্ভাব্য স্টেশনের তালিকা: ${validStations}

      নির্দেশনা:
      ১. গত ১ ঘণ্টার ফেসবুক পোস্ট (Bangladesh Railway Fan Group), ট্র্যাকিং ওয়েবসাইট বা রেলওয়ে কমিউনিটি আপডেট চেক করুন।
      ২. উত্তরটি এই JSON ফরম্যাটে দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.95,
        "reason": "আপনার পাওয়া তথ্যের সংক্ষিপ্ত সারসংক্ষেপ বাংলায়",
        "likelyCurrentStation": "উপরের স্টেশনের তালিকা থেকে হুবহু একটি নাম"
      }
      ৩. likelyCurrentStation হিসেবে অবশ্যই আমার দেওয়া তালিকার নাম ব্যবহার করবেন। যদি নিশ্চিত না হন তবে এই ফিল্ডটি খালি রাখুন।
      ৪. কোনো সুনির্দিষ্ট ডাটা না পেলে কেবল 'reason' ফিল্ডে কারণ লিখুন (যেমন: "আজ ট্রেনটির কোনো আপডেট পাওয়া যায়নি")।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }]
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      let parsedJson: any = null;
      const jsonMatch = text.match(/\{[\s\S]*?\}/);
      if (jsonMatch) {
        try {
          parsedJson = JSON.parse(jsonMatch[0]);
        } catch (e) {
          console.warn("JSON extraction failed");
        }
      }

      if (parsedJson && (parsedJson.likelyCurrentStation || parsedJson.reason)) {
        setAiInference({
          delayMinutes: parsedJson.delayMinutes || 0,
          confidence: parsedJson.confidence || 0.8,
          reason: parsedJson.reason || text.split('{')[0].trim(),
          likelyCurrentStation: parsedJson.likelyCurrentStation,
          isAI: true,
          sources,
          rawText: text
        });
      } else {
        setAiInference({
          delayMinutes: 0,
          confidence: 0.5,
          reason: text.replace(/\{[\s\S]*?\}/, '').trim() || "তথ্য পাওয়া গেছে কিন্তু স্টেশন নিশ্চিত করা যায়নি। নিচে সোর্স দেখুন।",
          isAI: true,
          sources,
          rawText: text
        });
      }
    } catch (e: any) {
      console.error("Inference Error:", e);
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: 'এআই সার্ভিসের সাথে সংযোগ বিচ্ছিন্ন হয়েছে। অনুগ্রহ করে আবার চেষ্টা করুন।', 
        isAI: false, 
        sources: [], 
        rawText: '' 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    // Logic 1: AI Match (Strict or Partial)
    if (inference.isAI && inference.likelyCurrentStation && inference.confidence > 0.4) {
      const query = inference.likelyCurrentStation.toLowerCase().trim();
      const foundIdx = stations.findIndex(s => {
        const station = s.toLowerCase();
        return station.includes(query) || query.includes(station);
      });

      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ রিপোর্ট: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    // Logic 2: Schedule Fallback
    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '৮': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const parts = normTime.split(' ');
    if (parts.length < 2) return null;

    const [t, ampm] = parts;
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;

    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায় (শিডিউল)', stationIndex: 0 };

    // Estimate progress based on typical travel time (25 mins per station)
    const idx = Math.min(Math.max(0, Math.floor(diff / 25)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) {
      console.warn("Prayer API failed, keeping current data.");
    }
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      let prompt = "";
      let schema: any = null;

      if (category === 'market_price') {
        prompt = "Fetch current market prices for essential food items in Rajbari, Bangladesh. Respond in JSON.";
        schema = {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              unit: { type: Type.STRING },
              priceRange: { type: Type.STRING },
              trend: { type: Type.STRING }
            },
            required: ['name', 'unit', 'priceRange', 'trend']
          }
        };
      }

      if (prompt && schema) {
        const response = await db.callAI({
          contents: [{ parts: [{ text: prompt }] }],
          responseMimeType: "application/json",
          responseSchema: schema
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Update Failed:", e);
    } finally {
      setIsInferring(false);
    }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 animate-slide-up group">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className="text-[8px] text-slate-400 font-bold uppercase">ছুটি</p>
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all">
              <Radar className="w-4 h-4 animate-pulse" /> লাইভ রিপোর্ট চেক করুন
            </button>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group transition-all hover:bg-lime-50 dark:hover:bg-lime-950/20 shadow-sm">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl"><ShoppingBasket className="w-6 h-6" /></div>
                <div>
                   <h4 className="font-bold dark:text-white text-lg">{item.name}</h4>
                   <p className="text-xs text-slate-400 font-bold uppercase">{item.unit}</p>
                </div>
             </div>
             <div className="text-right">
                <div className="flex items-center justify-end gap-1.5 mb-1">
                   {item.isAI && <Sparkles className="w-3 h-3 text-amber-500 animate-pulse" />}
                   <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.priceRange}</p>
                </div>
             </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group shadow-sm transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
               <div><h4 className="font-bold dark:text-white text-lg">{item.name || item.title}</h4><p className="text-xs text-slate-400 font-bold">{item.address || item.details || item.number || item.mobile}</p></div>
            </div>
            {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-slate-800 rounded-2xl text-indigo-600 active:scale-90 transition-all shadow-md"><Phone className="w-6 h-6" /></a>}
          </div>
        );
    }
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="flex items-center justify-between mb-8 px-2">
         <div className="flex flex-col">
           <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">
             {category === 'market_price' ? 'লাইভ বাজারদর' : category === 'prayer' ? 'নামাজের সময়' : category === 'notices' ? 'সর্বশেষ নোটিশ' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 'তালিকা'}
           </h3>
           <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em]">District Portal</p>
         </div>
         {(['market_price', 'notices'].includes(category)) && (
           <button onClick={updateWithAI} disabled={isInferring} className={`p-4 bg-indigo-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all ${isInferring ? 'animate-spin opacity-50' : ''}`}>
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
         {category === 'prayer' && (
           <button onClick={fetchLivePrayerTimes} className="p-4 bg-violet-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all">
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
      </div>

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[3rem] p-6 shadow-3xl flex flex-col max-h-[90vh] animate-slide-up relative border border-white/10">
            <button onClick={() => setSelectedTrain(null)} className="absolute right-6 top-6 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-500 z-10"><X className="w-6 h-6" /></button>
            <div className="flex items-center gap-4 mb-8">
              <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl">
                {isInferring ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrainFront className="w-6 h-6" />}
              </div>
              <div>
                <h4 className="text-xl font-black dark:text-white uppercase tracking-tighter">{selectedTrain.name}</h4>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full animate-ping ${isInferring ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isInferring ? 'ইন্টারনেট সার্চ করা হচ্ছে...' : 'লাইভ ট্র্যাকিং সক্রিয়'}</span>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto no-scrollbar pr-1">
              <div className="space-y-6">
                <div className={`p-6 rounded-[2.5rem] border-2 bg-indigo-50 dark:bg-indigo-900/10 border-indigo-100 dark:border-indigo-900/30 shadow-inner`}>
                  <div className="flex justify-between items-center mb-3">
                     <p className="text-[9px] font-black uppercase tracking-widest text-indigo-500 flex items-center gap-1.5"><History className="w-3.5 h-3.5" /> এআই স্মার্ট ড্যাশবোর্ড</p>
                     <button onClick={() => runAIInference(selectedTrain)} className="p-2 bg-white dark:bg-slate-800 rounded-lg text-indigo-600"><RefreshCw className={`w-3.5 h-3.5 ${isInferring ? 'animate-spin' : ''}`} /></button>
                  </div>
                  <h3 className="text-xl font-black dark:text-white leading-tight mb-4">{liveInfo?.status || 'লোডিং...'}</h3>

                  <div className="p-5 bg-white/70 dark:bg-white/5 rounded-[2rem] border border-white/50 shadow-inner">
                    <div className="flex items-center gap-1.5 mb-2 text-indigo-500">
                        <Sparkles className="w-4 h-4" />
                        <span className="text-[9px] font-black uppercase tracking-widest">লাইভ রিপোর্ট</span>
                    </div>
                    <p className="text-[13px] font-bold text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
                      {aiInference.reason || (isInferring ? 'ট্রেনের সর্বশেষ আপডেট সোশ্যাল মিডিয়া ও রেলওয়ে ফ্যান গ্রুপ থেকে খোঁজা হচ্ছে...' : 'কোনো তথ্য পাওয়া যায়নি।')}
                    </p>
                    {aiInference.sources && aiInference.sources.length > 0 && (
                      <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-200/50">
                        {aiInference.sources.map((chunk: any, sidx: number) => (
                          chunk.web && (
                            <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-[8px] font-black text-indigo-600 bg-white dark:bg-slate-800 px-2 py-1 rounded-md border border-indigo-100 hover:bg-indigo-50">
                              <Globe className="w-2 h-2" /> Source {sidx+1}
                            </a>
                          )
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {liveInfo && (
                  <div className="px-8 py-6 relative">
                    <div className="absolute left-[38px] top-8 bottom-8 w-1.5 bg-slate-100 dark:bg-slate-800 rounded-full"></div>
                    <div className="absolute left-[38px] top-8 w-1.5 bg-indigo-600 rounded-full transition-all duration-1000" style={{ height: `${liveInfo.progress}%` }}></div>
                    <div className="space-y-10 relative">
                      {selectedTrain.detailedRoute?.split(',').map((s, i) => (
                        <div key={i} className="flex items-center gap-8">
                          <div className={`w-6 h-6 rounded-full border-4 z-10 ${i < (liveInfo?.stationIndex || 0) ? 'bg-indigo-600 border-indigo-100' : i === (liveInfo?.stationIndex || 0) ? 'bg-white border-indigo-600 scale-125 shadow-lg' : 'bg-white border-slate-200'}`}></div>
                          <h5 className={`font-black uppercase tracking-tight ${i === (liveInfo?.stationIndex || 0) ? 'text-indigo-600 text-sm' : 'text-slate-400 text-[12px]'}`}>{s.trim()}</h5>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {isInferring && !selectedTrain && (
             <div className="bg-indigo-50 dark:bg-indigo-900/10 p-8 rounded-[2.5rem] border border-indigo-100 dark:border-indigo-900/30 text-center mb-6">
                <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mx-auto mb-4" />
                <p className="text-sm font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest">সর্বশেষ তথ্য খোঁজা হচ্ছে...</p>
             </div>
           )}
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import 'dotenv/config';
import express from 'express';
import cors from 'cors';
import path from 'path';
import { fileURLToPath } from 'url';
import { GoogleGenAI } from '@google/genai';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();
const port = process.env.PORT || 3001;

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'dist')));

/**
 * সিকিউর এআই এন্ডপয়েন্ট
 * এই এন্ডপয়েন্টটি ফ্রন্টএন্ড থেকে আসা রিকোয়েস্ট গ্রহণ করে এবং জেমিনি এপিআই কল করে।
 */
app.post('/api/ai', async (req, res) => {
    const { contents, systemInstruction, tools, responseSchema, responseMimeType } = req.body;

    if (!process.env.API_KEY) {
        return res.status(500).json({ error: "Server Configuration Error: API_KEY is missing." });
    }

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // প্রডাকশন কোয়ালিটির জন্য gemini-3-pro-preview ব্যবহার করা হচ্ছে
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: contents,
            config: {
                systemInstruction: systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। 
                রাজবাড়ী জেলার ট্রেন ট্র্যাকিং এবং স্থানীয় তথ্যের জন্য গুগল সার্চ ব্যবহার করুন। 
                সর্বদা বাংলায় উত্তর দিন। ডাটা প্রদানের সময় সঠিকতা বজায় রাখুন।`,
                tools: tools || [{ googleSearch: {} }],
                responseSchema: responseSchema,
                responseMimeType: responseMimeType,
                temperature: 0.1, // ডাটা সঠিক রাখার জন্য কম টেম্পারেচার
            }
        });

        res.json({
            text: response.text || "",
            groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
        });
    } catch (error) {
        console.error("Gemini API Error:", error.message);
        res.status(500).json({ error: error.message || "Gemini API call failed." });
    }
});

// মক ডাটাবেজ রাউট
app.get('/api/db', (req, res) => res.json([]));

// ক্লায়েন্ট সাইড রাউটিং সাপোর্ট
app.get('*', (req, res) => {
    res.sendFile(path.join(__dirname, 'dist', 'index.html'));
});

app.listen(port, () => console.log(`Rajbari Smart Server active on port ${port}`));

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference, Type } from '../types';
import { db } from '../db';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ ইঞ্জিন ব্যবহার করে ট্রেনের অবস্থান অনুসন্ধান করা হচ্ছে...', isAI: true, sources: [], rawText: '' });

    const validStations = train.detailedRoute || "";

    try {
      const prompt = `রাজবাড়ী জেলার "${train.name} (${train.id})" ট্রেনটির বর্তমান অবস্থান কি?

      স্টেশনের তালিকা: ${validStations}

      নির্দেশনা:
      ১. গত ১ ঘণ্টার ফেসবুক আপডেট বা লাইভ ট্র্যাকার ডাটা চেক করুন।
      ২. উত্তরটি এই JSON ফরম্যাটে দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.9,
        "reason": "আপনার পাওয়া তথ্যের সংক্ষিপ্ত সারসংক্ষেপ বাংলায়",
        "likelyCurrentStation": "উপরের স্টেশনের তালিকা থেকে একটি নাম"
      }
      ৩. কেবল JSON টি আউটপুটে দিন।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন প্রোফেশনাল রেলওয়ে অ্যাসিস্ট্যান্ট। গুগল সার্চ ব্যবহার করে নিখুঁত লাইভ লোকেশন ডাটা প্রদান করেন।"
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      let parsedJson: any = null;
      // Regex to extract JSON even if AI adds extra text
      const jsonMatch = text.match(/\{[\s\S]*?\}/);
      if (jsonMatch) {
        try {
          parsedJson = JSON.parse(jsonMatch[0]);
        } catch (e) {
          console.warn("JSON parsing failed, fallback to text");
        }
      }

      if (parsedJson && (parsedJson.likelyCurrentStation || parsedJson.reason)) {
        setAiInference({
          delayMinutes: parsedJson.delayMinutes || 0,
          confidence: parsedJson.confidence || 0.8,
          reason: parsedJson.reason || text.split('{')[0].trim(),
          likelyCurrentStation: parsedJson.likelyCurrentStation,
          isAI: true,
          sources,
          rawText: text
        });
      } else {
        // Fallback for non-JSON response
        setAiInference({
          delayMinutes: 0,
          confidence: 0.6,
          reason: text.replace(/\{[\s\S]*?\}/, '').trim() || "তথ্য পাওয়া গেছে কিন্তু নির্দিষ্ট স্টেশনে ম্যাচ করানো যায়নি।",
          isAI: true,
          sources,
          rawText: text
        });
      }
    } catch (e: any) {
      console.error("AI Error:", e);
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভার থেকে ডাটা পাওয়া যায়নি। পুনরায় চেষ্টা করুন।', isAI: false, sources: [], rawText: '' });
    } finally { 
      setIsInferring(false); 
    }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    // Logic: Fuzzy matching station name from AI
    if (inference.isAI && inference.likelyCurrentStation) {
      const aiStation = inference.likelyCurrentStation.toLowerCase();
      const foundIdx = stations.findIndex(s => {
        const local = s.toLowerCase();
        return local.includes(aiStation) || aiStation.includes(local);
      });

      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ লোকেশন: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    // Schedule Fallback
    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '৮': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const parts = normTime.split(' ');
    if (parts.length < 2) return null;

    const [t, ampm] = parts;
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;

    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায় (শিডিউল)', stationIndex: 0 };
    const idx = Math.min(Math.max(0, Math.floor(diff / 25)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) {
      console.warn("Prayer API failed.");
    }
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      if (category === 'market_price') {
        const response = await db.callAI({
          contents: [{ parts: [{ text: "Fetch current market prices for Rajbari, Bangladesh. Response in JSON." }] }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                unit: { type: Type.STRING },
                priceRange: { type: Type.STRING },
                trend: { type: Type.STRING }
              },
              required: ['name', 'unit', 'priceRange', 'trend']
            }
          }
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI update failed.");
    } finally {
      setIsInferring(false);
    }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 group">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay === 'নাই' ? 'সপ্তাহে ৭ দিন' : `${item.offDay} বন্ধ`}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all">
              <Radar className="w-4 h-4 animate-pulse" /> লাইভ রিপোর্ট চেক করুন
            </button>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group shadow-sm transition-all hover:bg-lime-50 dark:hover:bg-lime-950/20">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl"><ShoppingBasket className="w-6 h-6" /></div>
                <div>
                   <h4 className="font-bold dark:text-white text-lg">{item.name}</h4>
                   <p className="text-xs text-slate-400 font-bold uppercase">{item.unit}</p>
                </div>
             </div>
             <div className="text-right">
                <div className="flex items-center justify-end gap-1.5 mb-1">
                   {item.isAI && <Sparkles className="w-3 h-3 text-amber-500 animate-pulse" />}
                   <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.priceRange}</p>
                </div>
             </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group shadow-sm transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
               <div><h4 className="font-bold dark:text-white text-lg">{item.name || item.title}</h4><p className="text-xs text-slate-400 font-bold">{item.address || item.details || item.number || item.mobile}</p></div>
            </div>
            {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-slate-800 rounded-2xl text-indigo-600 active:scale-90 transition-all shadow-md"><Phone className="w-6 h-6" /></a>}
          </div>
        );
    }
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="flex items-center justify-between mb-8 px-2">
         <div className="flex flex-col">
           <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">
             {category === 'market_price' ? 'লাইভ বাজারদর' : category === 'prayer' ? 'নামাজের সময়' : category === 'notices' ? 'সর্বশেষ নোটিশ' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 'তালিকা'}
           </h3>
           <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em]">District Portal</p>
         </div>
         {category === 'market_price' && (
           <button onClick={updateWithAI} disabled={isInferring} className={`p-4 bg-indigo-600 text-white rounded-2xl shadow-xl active:scale-90 transition-all ${isInferring ? 'animate-spin opacity-50' : ''}`}>
             <RefreshCw className="w-5 h-5" />
           </button>
         )}
      </div>

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[3rem] p-6 shadow-3xl flex flex-col max-h-[90vh] animate-slide-up relative border border-white/10 overflow-hidden">
            <button onClick={() => setSelectedTrain(null)} className="absolute right-6 top-6 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-500 z-10 hover:bg-rose-50 hover:text-rose-500 transition-colors"><X className="w-6 h-6" /></button>

            <div className="flex items-center gap-4 mb-8">
              <div className="bg-indigo-600 p-4 rounded-2xl text-white shadow-xl">
                {isInferring ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrainFront className="w-6 h-6" />}
              </div>
              <div>
                <h4 className="text-xl font-black dark:text-white uppercase tracking-tighter">{selectedTrain.name}</h4>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full animate-ping ${isInferring ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isInferring ? 'তথ্য অনুসন্ধান করা হচ্ছে...' : 'লাইভ ট্র্যাকিং সক্রিয়'}</span>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto no-scrollbar pr-1">
              <div className="space-y-6">
                <div className={`p-6 rounded-[2.5rem] border-2 bg-indigo-50 dark:bg-indigo-900/10 border-indigo-100 dark:border-indigo-900/30 shadow-inner relative overflow-hidden`}>
                  <div className="flex justify-between items-center mb-3">
                     <p className="text-[9px] font-black uppercase tracking-widest text-indigo-500 flex items-center gap-1.5"><History className="w-3.5 h-3.5" /> এআই স্মার্ট ড্যাশবোর্ড</p>
                     <button onClick={() => runAIInference(selectedTrain)} disabled={isInferring} className="p-2 bg-white dark:bg-slate-800 rounded-lg text-indigo-600 shadow-sm"><RefreshCw className={`w-3.5 h-3.5 ${isInferring ? 'animate-spin' : ''}`} /></button>
                  </div>
                  <h3 className="text-xl font-black dark:text-white leading-tight mb-4">{liveInfo?.status || 'লোডিং...'}</h3>

                  <div className="p-5 bg-white/70 dark:bg-white/5 rounded-[2rem] border border-white/50 shadow-inner">
                    <div className="flex items-center gap-1.5 mb-2 text-indigo-500">
                        <Sparkles className="w-4 h-4" />
                        <span className="text-[9px] font-black uppercase tracking-widest">লাইভ রিপোর্ট</span>
                    </div>
                    <p className="text-[13px] font-bold text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
                      {aiInference.reason || (isInferring ? 'সোশ্যাল মিডিয়া ও ট্র্যাকার থেকে তথ্য সংগৃহীত হচ্ছে...' : 'আপাতত কোনো লাইভ রিপোর্ট পাওয়া যায়নি।')}
                    </p>
                    {aiInference.sources && aiInference.sources.length > 0 && (
                      <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-200/50">
                        {aiInference.sources.map((chunk: any, sidx: number) => (
                          chunk.web && (
                            <a key={sidx} href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-[8px] font-black text-indigo-600 bg-white dark:bg-slate-800 px-2 py-1 rounded-md border border-indigo-100 hover:bg-indigo-50">
                              <Globe className="w-2 h-2" /> Source {sidx+1}
                            </a>
                          )
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {liveInfo && (
                  <div className="px-8 py-6 relative">
                    <div className="absolute left-[38px] top-8 bottom-8 w-1.5 bg-slate-100 dark:bg-slate-800 rounded-full"></div>
                    <div className="absolute left-[38px] top-8 w-1.5 bg-indigo-600 rounded-full transition-all duration-1000" style={{ height: `${liveInfo.progress}%` }}></div>
                    <div className="space-y-10 relative">
                      {selectedTrain.detailedRoute?.split(',').map((s, i) => (
                        <div key={i} className="flex items-center gap-8">
                          <div className={`w-6 h-6 rounded-full border-4 z-10 transition-all duration-500 ${i < (liveInfo?.stationIndex || 0) ? 'bg-indigo-600 border-indigo-100' : i === (liveInfo?.stationIndex || 0) ? 'bg-white border-indigo-600 scale-125 shadow-lg animate-pulse' : 'bg-white border-slate-200'}`}></div>
                          <h5 className={`font-black uppercase tracking-tight transition-all ${i === (liveInfo?.stationIndex || 0) ? 'text-indigo-600 text-sm' : 'text-slate-400 text-[12px]'}`}>{s.trim()}</h5>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
            <button onClick={() => setSelectedTrain(null)} className="mt-6 w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl active:scale-95 transition-all">বন্ধ করুন</button>
          </div>
        </div>
      )}

      {loading ? (
        <div className="space-y-6">{[1,2,3,4].map(i => <div key={i} className="h-40 shimmer rounded-[2.5rem]" />)}</div>
      ) : (
        <div className="space-y-4 animate-slide-up">
           {data.map(item => renderItem(item))}
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import { RAJBARI_DATA } from './constants';
import { GoogleGenAI } from "@google/genai";

// এপিআই কী সরাসরি এনভায়রনমেন্ট থেকে নেওয়া হচ্ছে
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const db = {
  /**
   * সরাসরি জেমিনি এসডিকে ব্যবহার করে এআই কল
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', // উন্নত সার্চ এবং রেজনিং এর জন্য প্রিমিয়াম মডেল
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। গুগল সার্চ ব্যবহার করে সঠিক তথ্য দিন।",
          tools: params.tools || [{ googleSearch: {} }],
          responseSchema: params.responseSchema,
          responseMimeType: params.responseMimeType,
          temperature: 0.1
        }
      });

      return {
        text: response.text,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata
      };
    } catch (error: any) {
      console.error("Gemini SDK Error:", error);
      throw new Error(error.message || "এআই সার্ভিসে সংযোগ করা সম্ভব হচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    const defaultData = (RAJBARI_DATA as any)[category] || [];
    // এখানে সার্ভার ডাটাবেজ থাকলে কল করা যেত, আপাতত অফলাইন ডাটা রিটার্ন করছে
    return defaultData;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket,
  ArrowUpRight,
  ArrowDownRight,
  Megaphone,
  Briefcase,
  ExternalLink,
  AlertCircle
} from 'lucide-react';
import { Category, Train, AIInference, Type } from '../types';
import { db } from '../db';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[], rawText?: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    rawText: ''
  });
  const [liveInfo, setLiveInfo] = useState<{currentStation: string, progress: number, status: string, nextStation?: string, stationIndex: number, isOffDay?: boolean, lastUpdated?: string} | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);
      if (selectedTrain) {
        setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্চ ইঞ্জিন ব্যবহার করে ট্রেনের অবস্থান অনুসন্ধান করা হচ্ছে...', isAI: true, sources: [], rawText: '' });

    const validStations = train.detailedRoute || "";

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। 
      রাজবাড়ী জেলার "${train.name} (${train.id})" ট্রেনটির বর্তমান লাইভ লোকেশন গুগল সার্চ করে বের করুন।

      স্টেশনের তালিকা: ${validStations}

      নির্দেশনা:
      ১. গত ১ ঘণ্টার ফেসবুক পোস্ট (Bangladesh Railway Fan Group), ট্র্যাকিং ওয়েবসাইট বা রেলওয়ে কমিউনিটি আপডেট চেক করুন।
      ২. উত্তরটি অবশ্যই এই JSON ফরম্যাটে দিন:
      {
        "delayMinutes": 0,
        "confidence": 0.95,
        "reason": "পাওয়া তথ্যের সংক্ষিপ্ত সারসংক্ষেপ বাংলায়",
        "likelyCurrentStation": "তালিকা থেকে একটি নাম"
      }
      ৩. likelyCurrentStation হিসেবে অবশ্যই আমার দেওয়া স্টেশনের তালিকা থেকে হুবহু একটি নাম ব্যবহার করবেন।
      ৪. সুনির্দিষ্ট ডাটা না পেলে 'reason' ফিল্ডে বিস্তারিত লিখুন এবং likelyCurrentStation খালি রাখুন।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে অ্যাসিস্ট্যান্ট। গুগল সার্চ ব্যবহার করে ট্রেনের সঠিক লাইভ রিপোর্ট প্রদান করেন।"
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      let parsedJson: any = null;
      const jsonMatch = text.match(/\{[\s\S]*?\}/);
      if (jsonMatch) {
        try {
          parsedJson = JSON.parse(jsonMatch[0]);
        } catch (e) {
          console.warn("JSON parsing failed");
        }
      }

      if (parsedJson) {
        setAiInference({
          delayMinutes: parsedJson.delayMinutes || 0,
          confidence: parsedJson.confidence || 0.8,
          reason: parsedJson.reason || "তথ্য সংগৃহীত হয়েছে।",
          likelyCurrentStation: parsedJson.likelyCurrentStation,
          isAI: true,
          sources,
          rawText: text
        });
      } else {
        setAiInference({
          delayMinutes: 0,
          confidence: 0.5,
          reason: text.replace(/\{[\s\S]*?\}/, '').trim() || "সার্চ রেজাল্ট পাওয়া গেছে কিন্তু নির্দিষ্ট কোনো লোকেশন নিশ্চিত করা যায়নি।",
          isAI: true,
          sources,
          rawText: text
        });
      }
    } catch (e: any) {
      console.error("AI Error:", e);
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: 'এআই সার্ভিসের সাথে সংযোগ করা সম্ভব হয়নি। আপনার ইন্টারনেট কানেকশন চেক করুন।', 
        isAI: false, 
        sources: [], 
        rawText: '' 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const calculateLiveLocation = (train: Train, inference: AIInference & { likelyCurrentStation?: string }) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || [];
    if (stations.length === 0) return null;

    // AI Match
    if (inference.isAI && inference.likelyCurrentStation) {
      const aiStation = inference.likelyCurrentStation.toLowerCase();
      const foundIdx = stations.findIndex(s => {
        const local = s.toLowerCase();
        return local.includes(aiStation) || aiStation.includes(local);
      });

      if (foundIdx !== -1) {
        return { 
          currentStation: stations[foundIdx], 
          progress: Math.floor((foundIdx / (stations.length - 1)) * 100), 
          status: `লাইভ রিপোর্ট: ${stations[foundIdx]}`, 
          stationIndex: foundIdx 
        };
      }
    }

    // Schedule Fallback
    const bnDigits: {[key: string]: string} = { '০': '0', '১': '1', '২': '2', '৩': '3', '৪': '4', '৫': '5', '৬': '6', '৭': '7', '৮': '8', '৯': '9' };
    const normTime = train.departure === 'Start' ? '06:00 AM' : train.departure.replace(/[০-৯]/g, m => bnDigits[m]);
    const parts = normTime.split(' ');
    if (parts.length < 2) return null;

    const [t, ampm] = parts;
    let [h, m] = t.split(':').map(Number);
    if (ampm === 'PM' && h < 12) h += 12;
    if (ampm === 'AM' && h === 12) h = 0;

    const dep = new Date(currentTime);
    dep.setHours(h, m, 0, 0);
    const diff = Math.floor((currentTime.getTime() - dep.getTime()) / 60000);

    if (diff < 0) return { currentStation: stations[0], progress: 0, status: 'ছাড়ার অপেক্ষায় (শিডিউল)', stationIndex: 0 };
    const idx = Math.min(Math.max(0, Math.floor(diff / 25)), stations.length - 1);
    return { currentStation: stations[idx], progress: Math.floor((idx / (stations.length - 1)) * 100), status: 'সম্ভাব্য অবস্থান (শিডিউল)', stationIndex: idx };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) {
      console.warn("Prayer API failed.");
    }
  };

  const updateWithAI = async () => {
    setIsInferring(true);
    try {
      if (category === 'market_price') {
        const response = await db.callAI({
          contents: [{ parts: [{ text: "Fetch current market prices for Rajbari, Bangladesh. Response in JSON." }] }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                unit: { type: Type.STRING },
                priceRange: { type: Type.STRING },
                trend: { type: Type.STRING }
              },
              required: ['name', 'unit', 'priceRange', 'trend']
            }
          }
        });
        const aiData = JSON.parse(response.text || '[]');
        if (aiData.length > 0) {
          setData(aiData.map((item: any, i: number) => ({ ...item, id: `ai-${i}`, isAI: true })));
        }
      }
    } catch (e) {
      console.error("AI Update Failed");
    } finally {
      setIsInferring(false);
    }
  };

  const renderItem = (item: any) => {
    switch (category) {
      case 'trains':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-6 group transition-all hover:border-indigo-200">
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner transition-transform group-hover:scale-110"><TrainFront className="w-6 h-6" /></div>
              <div className="flex-1">
                <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
              <div className="text-right">
                 <p className={`text-[10px] font-black uppercase ${item.offDay === 'নাই' ? 'text-emerald-500' : 'text-rose-500'}`}>{item.offDay === 'নাই' ? 'সপ্তাহে ৭ দিন' : `${item.offDay} বন্ধ`}</p>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-5">
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">আগমন</p>
                <p className="text-xl font-black dark:text-white tracking-tighter">{item.arrival || '--'}</p>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
                <p className="text-[8px] text-slate-400 font-bold uppercase mb-1">প্রস্থান</p>
                <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.departure}</p>
              </div>
            </div>
            <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all hover:bg-indigo-700">
              <Radar className="w-4 h-4 animate-pulse" /> লাইভ রিপোর্ট চেক করুন
            </button>
          </div>
        );
      case 'market_price':
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 flex items-center justify-between mb-4 group shadow-sm transition-all hover:bg-lime-50 dark:hover:bg-lime-950/20">
             <div className="flex items-center gap-4">
                <div className="p-4 bg-lime-50 dark:bg-lime-900/20 text-lime-600 rounded-2xl"><ShoppingBasket className="w-6 h-6" /></div>
                <div>
                   <h4 className="font-bold dark:text-white text-lg">{item.name}</h4>
                   <p className="text-xs text-slate-400 font-bold uppercase">{item.unit}</p>
                </div>
             </div>
             <div className="text-right">
                <div className="flex items-center justify-end gap-1.5 mb-1">
                   {item.isAI && <Sparkles className="w-3 h-3 text-amber-500 animate-pulse" />}
                   <p className="text-xl font-black text-indigo-600 tracking-tighter">{item.priceRange}</p>
                </div>
             </div>
          </div>
        );
      default:
        return (
          <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] premium-shadow border border-slate-50 dark:border-slate-800 mb-4 flex items-center justify-between group shadow-sm transition-all hover:-translate-y-1">
            <div className="flex items-center gap-4">
               <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl text-indigo-600"><Info className="w-5 h-5" /></div>
               <div><h4 className="font-bold dark:text-white text-lg">{item.name || item.title}</h4><p className="text-xs text-slate-400 font-bold">{item.address || item.details || item.number || item.mobile}</p></div>
            </div>
            {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-slate-800 rounded-2xl text-indigo-600 active:scale-90 transition-all shadow-md"><Phone className="w-6 h-6" /></a>}
          </div>
        );
    }
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="flex items-center justify-between mb-8 px-2">
         <div className="flex flex-col">
           <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase">
             {category === 'market_price' ? 'লাইভ বাজারদর' : category === 'prayer' ? 'নামাজের সময়' : category === 'notices' ? 'সর্বশেষ নোটিশ' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 'তালিকা'}
           </h3>
           <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">District Portal</p>
         </div>
         {category === 'market_price' && (
