import { RAJBARI_DATA } from './constants';
import { GoogleGenAI } from "@google/genai";

/**
 * রাজবাড়ী জেলা তথ্য সেবা - ডাটাবেজ ও এআই ম্যানেজার
 */

// Vite বা অন্য বিল্ড টুলের ক্ষেত্রে এনভায়রনমেন্ট ভেরিয়েবল চেক করা
const API_KEY = process.env.API_KEY || "";

export const db = {
  /**
   * সরাসরি জেমিনি এসডিকে ব্যবহার করে এআই কল
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    try {
      if (!API_KEY) {
        throw new Error("API Key পাওয়া যায়নি। অনুগ্রহ করে এনভায়রনমেন্ট ভেরিয়েবল চেক করুন।");
      }

      const ai = new GoogleGenAI({ apiKey: API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', 
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। গুগল সার্চ ব্যবহার করে সঠিক তথ্য দিন।",
          tools: params.tools || [{ googleSearch: {} }],
          responseSchema: params.responseSchema,
          responseMimeType: params.responseMimeType,
          temperature: 0.1
        }
      });

      return {
        text: response.text,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata
      };
    } catch (error: any) {
      console.error("AI Call Error:", error);
      // যদি লিমিট শেষ হয়ে যায় বা অন্য সমস্যা হয়
      if (error.message?.includes("429")) {
        throw new Error("এআই সার্ভারের লিমিট শেষ হয়েছে। কিছুক্ষণ পর আবার চেষ্টা করুন।");
      }
      throw new Error(error.message || "এআই সার্ভিসে সংযোগ করা সম্ভব হচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    // এখানে ভবিষ্যতে আপনার লোকাল বা ক্লাউড ডাটাবেজ কানেক্ট করতে পারবেন
    const defaultData = (RAJBARI_DATA as any)[category] || [];
    return defaultData;
  }
};

