  const getGreeting = () => {
    const hour = currentTime.getHours();
    if (hour >= 5 && hour < 12) return 'শুভ সকাল';
    if (hour >= 12 && hour < 16) return 'শুভ দুপুর';
    if (hour >= 16 && hour < 18) return 'শুভ অপরাহ্ন';
