import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  ShoppingBasket
} from 'lucide-react';
import { Category, Train, AIInference, Type } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });
  const [liveInfo, setLiveInfo] = useState<any>(null);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (selectedTrain) {
      setLiveInfo(calculateLiveLocation(selectedTrain, aiInference));
    }
  }, [currentTime, selectedTrain, aiInference]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);
      if (category === 'prayer') await fetchLivePrayerTimes();
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'অনুসন্ধান করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনের বর্তমান লোকেশন গুগল সার্চ করে বের করুন। JSON ফরম্যাটে উত্তর দিন।`;
      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন রেলওয়ে অ্যাসিস্ট্যান্ট।"
      });

      const text = response.text || '';
      const sources = response.groundingMetadata?.groundingChunks || [];

      setAiInference({
        delayMinutes: 0,
        confidence: 0.9,
        reason: text.slice(0, 200),
        isAI: true,
        sources: sources
      });
    } catch (e) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'তথ্য পাওয়া যায়নি।', isAI: false, sources: [] });
    } finally {
      setIsInferring(false);
    }
  };

  const calculateLiveLocation = (train: Train, inference: any) => {
    const stations = train.detailedRoute?.split(',').map(s => s.trim()) || ['রাজবাড়ী'];
    return {
      currentStation: stations[0],
      progress: 30,
      status: 'ট্রেনটি পথে রয়েছে',
      stationIndex: 0
    };
  };

  const fetchLivePrayerTimes = async () => {
    try {
      const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
      const json = await res.json();
      if (json.code === 200) {
        const t = json.data.timings;
        setData([
          { name: 'ফজর', time: t.Fajr, icon: '🌅' },
          { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
          { name: 'আসর', time: t.Asr, icon: '🌤️' },
          { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
          { name: 'এশা', time: t.Isha, icon: '🌙' },
        ]);
      }
    } catch (e) { console.warn(e); }
  };

  const renderItem = (item: any) => {
    if (category === 'trains') {
      return (
        <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-xl"><TrainFront /></div>
            <div>
              <h4 className="font-bold dark:text-white">{item.name}</h4>
              <p className="text-xs text-slate-400">{item.route}</p>
            </div>
          </div>
          <button onClick={() => { setSelectedTrain(item); runAIInference(item); }} className="w-full bg-indigo-600 text-white py-3 rounded-xl text-xs font-bold uppercase tracking-wider">
            লাইভ রিপোর্ট দেখুন
          </button>
        </div>
      );
    }
    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-2xl mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-slate-50 dark:bg-slate-800 rounded-lg"><Info className="w-5 h-5 text-indigo-500" /></div>
          <div>
            <h4 className="font-bold text-sm dark:text-white">{item.name || item.title}</h4>
            <p className="text-[10px] text-slate-400">{item.mobile || item.address || item.details}</p>
          </div>
        </div>
        {(item.mobile || item.number) && (
          <a href={`tel:${item.mobile || item.number}`} className="p-3 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 rounded-full">
            <Phone className="w-5 h-5" />
          </a>
        )}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-32">
      <div className="mb-6">
        <h3 className="text-xl font-bold text-slate-800 dark:text-white uppercase tracking-tight">
          {category === 'emergency' ? 'জরুরি সেবা' : 'বিস্তারিত তালিকা'}
        </h3>
      </div>

      {loading ? (
        <div className="flex justify-center py-10"><Loader2 className="w-8 h-8 animate-spin text-indigo-600" /></div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? data.map(renderItem) : <p className="text-center text-slate-400 text-sm py-10">কোনো তথ্য পাওয়া যায়নি।</p>}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl p-6 relative">
            <button onClick={() => setSelectedTrain(null)} className="absolute top-4 right-4 p-2 bg-slate-100 dark:bg-slate-800 rounded-full"><X className="w-5 h-5" /></button>
            <h4 className="text-lg font-bold mb-4 dark:text-white">{selectedTrain.name}</h4>
            <div className="p-4 bg-indigo-50 dark:bg-indigo-950/50 rounded-2xl border border-indigo-100 dark:border-indigo-900/50">
              <p className="text-sm font-medium dark:text-slate-300 leading-relaxed">
                {isInferring ? 'তথ্য অনুসন্ধান করা হচ্ছে...' : aiInference.reason}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

