// Vercel Environment Variable
const API_KEY = (typeof process !== 'undefined' && process.env?.API_KEY) || "";

export const db = {
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    try {
      if (!API_KEY) {
        throw new Error("API_KEY is missing in Vercel environment.");
      }

      const ai = new GoogleGenAI({ apiKey: API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট।",
          tools: params.tools || [{ googleSearch: {} }],
          responseSchema: params.responseSchema,
          responseMimeType: params.responseMimeType,
          temperature: 0.1
        }
      });

      return {
        text: response.text || "",
        groundingMetadata: response.candidates?.[0]?.groundingMetadata
      };
    } catch (error: any) {
      console.error("AI Error:", error);
      throw error;
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

