          className="group bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all hover:border-indigo-400 hover:shadow-xl"
        >
          <div className="flex items-start justify-between">
            <div className="flex items-center gap-4">
              <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm">
                <TrainFront className="w-6 h-6" />
              </div>
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-none mb-1">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest mb-1">প্রস্থান সময়</p>
              <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
            </div>
          </div>
          <div className="flex items-center justify-between pt-4 border-t border-slate-50 dark:border-slate-800/50">
             <div className="flex items-center gap-2">
               <History className="w-3.5 h-3.5 text-slate-300" />
               <span className="text-[10px] font-bold text-slate-400">বন্ধ: {item.offDay}</span>
             </div>
             <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/30 px-5 py-2 rounded-full border border-indigo-100 dark:border-indigo-900/50">
               <Radar className="w-3 h-3 text-indigo-500 animate-pulse" />
               <span className="text-[9px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">লাইভ রাডার</span>
             </div>
          </div>
        </div>
      );
    }

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm hover:border-indigo-200 hover:shadow-md transition-all">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl shadow-inner">
            {item.icon || <Info className="w-6 h-6 text-indigo-500" />}
          </div>
          <div>
            <h4 className="font-bold text-slate-800 dark:text-white text-sm leading-tight">{item.name || item.title}</h4>
            <p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.mobile || item.address || item.time || item.details}</p>
          </div>
        </div>
        {(item.mobile || item.number) && (
          <a 
            href={`tel:${item.mobile || item.number}`} 
            className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl shadow-sm hover:scale-110 active:scale-90 transition-all border border-indigo-100 dark:border-indigo-900/50"
          >
            <Phone className="w-5 h-5" />
          </a>
        )}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase leading-none mb-1">
            {category === 'emergency' ? 'জরুরি সেবা' : category === 'trains' ? 'রেলওয়ে পোর্টাল' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">District Live Data</p>
        </div>
        <div className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800">
           <ClockIcon className="w-5 h-5 text-indigo-600 animate-pulse" />
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <div className="relative">
            <Loader2 className="w-14 h-14 animate-spin text-indigo-600" />
            <div className="absolute inset-0 flex items-center justify-center">
              <div className="w-2 h-2 bg-indigo-600 rounded-full animate-ping"></div>
            </div>
          </div>
          <p className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">প্রসেসিং হচ্ছে...</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? (
            data.map(renderItem)
          ) : (
            <div className="text-center py-20 bg-white dark:bg-slate-900 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
               <AlertCircle className="w-12 h-12 text-slate-200 mx-auto mb-4" />
               <p className="text-slate-400 font-bold">কোনো তথ্য খুঁজে পাওয়া যায়নি।</p>
            </div>
          )}
        </div>
      )}

      {renderTrainModal()}
    </div>
  );
};

