// Ensure process is defined for the browser environment if not already
const getApiKey = () => {
  try {
    // Priority: Vercel environment variable
    return process.env.API_KEY || "";
  } catch (e) {
    return "";
  }
};

export const db = {
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    const apiKey = getApiKey();
    if (!apiKey) {
      console.warn("AI Key Missing: Please ensure API_KEY is set in Vercel/System environment.");
