import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  RefreshCw,
  AlertCircle,
  ExternalLink,
  ChevronRight,
  CircleDot,
  Facebook
} from 'lucide-center';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';

// Using standard Lucide icons from esm.sh/lucide-react via index.html's importmap
import * as LucideIcons from 'lucide-react';

const { 
  Phone: PhoneIcon, 
  MapPin: MapPinIcon, 
  Clock: ClockIco, 
  Loader2: LoaderIcon, 
  TrainFront: TrainIcon, 
  X: XIcon, 
  Radar: RadarIcon, 
  Sparkles: SparklesIcon, 
  History: HistoryIcon, 
  Info: InfoIcon, 
  Globe: GlobeIcon, 
  ExternalLink: LinkIcon,
  Facebook: FBIcon,
  AlertCircle: AlertIcon
} = LucideIcons;

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { likelyCurrentStation?: string, sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);

      if (category === 'prayer') {
        try {
          const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
          const json = await res.json();
          if (json.code === 200) {
            const t = json.data.timings;
            setData([
              { name: 'ফজর', time: t.Fajr, icon: '🌅' },
              { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
              { name: 'আসর', time: t.Asr, icon: '🌤️' },
              { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
              { name: 'এশা', time: t.Isha, icon: '🌙' },
            ]);
          }
        } catch (e) {
          console.warn("Prayer fetch error", e);
        }
      }
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক ও সোশ্যাল মিডিয়া থেকে তথ্য খোঁজা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটি বর্তমানে কোথায় আছে? ফেসবুকের বিভিন্ন লোকাল ট্রেন ট্র্যাকিং গ্রুপ (যেমন: 'রাজবাড়ী রেলওয়ে সেবা' বা 'বাংলাদেশ রেলওয়ে ফ্যান গ্রুপ') থেকে লেটেস্ট পোস্ট বা কমেন্ট খুঁজে সঠিক অবস্থান এবং বিলম্ব (Delay) জানান। বাংলায় উত্তর দিন।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে ইনফরমেশন অফিসার। ফেসবুকের লোকাল গ্রুপ ও সোশ্যাল মিডিয়া থেকে ট্রেনের রিয়েল-টাইম ডাটা খুঁজে বের করাই আপনার প্রধান কাজ।"
      });

      const sources = response.groundingMetadata?.groundingChunks || [];

      setAiInference({
        delayMinutes: 0,
        confidence: 0.95,
        reason: response.text || 'তথ্য সংগ্রহ করা সম্ভব হয়নি।',
        isAI: true,
        sources: sources
      });
    } catch (e) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: 'দুঃখিত, ফেসবুক বা ইন্টারনেটে এই মুহূর্তে ট্রেনের লাইভ তথ্য পাওয়া যায়নি।', 
        isAI: false, 
        sources: [] 
      });
    } finally {
      setIsInferring(false);
    }
  };

  const renderRouteMap = (routeStr: string) => {
    const stations = routeStr.split(',').map(s => s.trim());
    return (
      <div className="mt-8 relative">
        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 px-2 flex items-center gap-2">
          <MapPinIcon className="w-3 h-3" /> রুট ম্যাপ ও স্টপসমূহ
        </h4>
        <div className="relative pl-8 space-y-6 before:absolute before:left-[15px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-100 dark:before:bg-slate-800">
          {stations.map((station, idx) => (
            <div key={idx} className="relative group">
              <div className={`absolute -left-[23px] top-1 w-4 h-4 rounded-full border-4 ${idx === 0 || idx === stations.length - 1 ? 'bg-indigo-600 border-indigo-100 dark:border-indigo-900' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'} z-10 shadow-sm`}></div>
              <div className="flex flex-col">
                <span className={`text-sm font-bold ${idx === 0 || idx === stations.length - 1 ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-700 dark:text-slate-300'}`}>
                  {station}
                </span>
                {idx === 0 && <span className="text-[9px] text-indigo-400 font-black uppercase tracking-tighter">যাত্রার শুরু</span>}
                {idx === stations.length - 1 && <span className="text-[9px] text-indigo-400 font-black uppercase tracking-tighter">গন্তব্য</span>}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderTrainModal = () => {
    if (!selectedTrain) return null;

    return (
      <div className="fixed inset-0 z-[200] bg-slate-950/95 backdrop-blur-xl flex items-end md:items-center justify-center p-0 md:p-6 animate-in fade-in duration-300">
        <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-t-[3.5rem] md:rounded-[3.5rem] overflow-hidden shadow-2xl relative max-h-[92vh] flex flex-col">
          <button 
            onClick={() => setSelectedTrain(null)}
            className="absolute top-8 right-8 p-3 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-500 z-50 hover:bg-rose-50 hover:text-rose-500 transition-all"
          >
            <XIcon className="w-6 h-6" />
          </button>

          <div className="p-8 pb-4 overflow-y-auto no-scrollbar">
            <div className="flex items-center gap-4 mb-8">
              <div className="p-4 bg-indigo-600 text-white rounded-[1.8rem] shadow-xl animate-swing">
                <TrainIcon className="w-8 h-8" />
              </div>
              <div>
                <h3 className="text-2xl font-black dark:text-white leading-tight tracking-tighter">{selectedTrain.name}</h3>
                <p className="text-indigo-500 font-black text-[10px] uppercase tracking-[0.3em]">{selectedTrain.route}</p>
              </div>
            </div>

            <div className="relative h-44 bg-slate-900 rounded-[2.8rem] mb-8 overflow-hidden flex items-center justify-center border border-slate-800 shadow-2xl">
               <div className="absolute inset-0 opacity-20">
                 <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border border-indigo-500 rounded-full animate-ping"></div>
                 <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-48 h-48 border border-indigo-500/50 rounded-full animate-ping [animation-delay:0.5s]"></div>
               </div>
               <div className="relative z-10 flex flex-col items-center">
                 <RadarIcon className={`w-14 h-14 text-indigo-400 ${isInferring ? 'animate-spin' : ''}`} style={{ animationDuration: '4s' }} />
                 <p className="text-indigo-400 font-black text-[10px] mt-4 uppercase tracking-[0.5em] animate-pulse">
                   {isInferring ? 'FACEBOOK SCANNING...' : 'SOCIAL TRACKING ACTIVE'}
                 </p>
               </div>
            </div>

            <div className="space-y-6">
               <div className="p-6 bg-indigo-50 dark:bg-indigo-950/30 rounded-[2.2rem] border border-indigo-100 dark:border-indigo-900/50 shadow-sm relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                    <SparklesIcon className="w-12 h-12 text-indigo-500" />
                 </div>
                 <div className="flex items-center gap-2 mb-3">
                   <FBIcon className="w-4 h-4 text-blue-600 fill-blue-600" />
                   <h4 className="text-[11px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">ফেসবুক ভিত্তিক লাইভ রিপোর্ট</h4>
                 </div>
                 <p className="text-sm font-bold dark:text-slate-200 leading-relaxed">
                   {isInferring ? 'ফেসবুকের বিভিন্ন রেলওয়ে গ্রুপ থেকে ট্রেনের সর্বশেষ আপডেট সংগ্রহ করা হচ্ছে...' : aiInference.reason}
                 </p>
               </div>

               {renderRouteMap(selectedTrain.detailedRoute)}

               {!isInferring && aiInference.sources && aiInference.sources.length > 0 && (
                 <div className="pb-10">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2 mb-4">তথ্যের উৎস (Source Links)</h4>
                    <div className="space-y-2">
                      {aiInference.sources.map((source: any, idx) => (
                        source.web && (
                          <a 
                            key={idx} 
                            href={source.web.uri} 
                            target="_blank" 
                            className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 rounded-2xl hover:border-indigo-300 transition-all group"
                          >
                            <div className="flex items-center gap-3">
                              {source.web.uri.includes('facebook.com') ? (
                                <FBIcon className="w-4 h-4 text-blue-600" />
                              ) : (
                                <GlobeIcon className="w-4 h-4 text-indigo-500" />
                              )}
                              <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300 truncate max-w-[200px]">{source.web.title || (source.web.uri.includes('facebook.com') ? 'ফেসবুক পোস্ট' : 'লাইভ ট্র্যাকিং সোর্স')}</span>
                            </div>
                            <LinkIcon className="w-3.5 h-3.5 text-slate-300 group-hover:text-indigo-500" />
                          </a>
                        )
                      ))}
                    </div>
                 </div>
               )}
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderItem = (item: any) => {
    if (category === 'trains') {
      return (
        <div 
          key={item.id} 
          onClick={() => { setSelectedTrain(item); runAIInference(item); }}
          className="group bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all hover:border-indigo-400 hover:shadow-xl"
        >
          <div className="flex items-start justify-between">
            <div className="flex items-center gap-4">
              <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm">
                <TrainIcon className="w-6 h-6" />
              </div>
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white text-lg leading-none mb-1">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
