import { RAJBARI_DATA } from './constants.tsx';
import { GoogleGenAI } from "@google/genai";

// Ensure process is defined for the browser environment if not already
const getApiKey = () => {
  try {
    return process.env.API_KEY || "";
  } catch (e) {
    return "";
  }
};

export const db = {
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    const apiKey = getApiKey();
    if (!apiKey) {
      console.warn("AI Key Missing: Please ensure API_KEY is set in your environment.");
    }

    const ai = new GoogleGenAI({ apiKey: apiKey });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: params.contents,
      config: {
        systemInstruction: params.systemInstruction || `আপনি রাজবাড়ী জেলার একজন প্রফেশনাল রেলওয়ে ইনফরমেশন স্পেশালিস্ট। 
        আপনার প্রধান কাজ হলো ফেসবুকের বিভিন্ন গ্রুপ (যেমন: 'রাজবাড়ী রেলওয়ে সেবা', 'বাংলাদেশ রেলওয়ে ফ্যান গ্রুপ', 'পাংশা-রাজবাড়ী ট্রেন আপডেট') থেকে ট্রেনের রিয়েল-টাইম তথ্য খুঁজে বের করা। 
        আপনি তথ্যের ভেরিফিকেশন টাইম (তথ্যটি কতক্ষণ আগের) এবং সঠিক স্টেশন লোকেশন নিশ্চিত করবেন। 
        তথ্যগুলো সর্বদা পয়েন্ট আকারে বাংলায় প্রদান করবেন।`,
        tools: params.tools || [{ googleSearch: {} }],
        responseSchema: params.responseSchema,
        responseMimeType: params.responseMimeType,
        temperature: 0.1,
        topP: 0.95
      }
    });

    return {
      text: response.text || "",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
    };
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  ExternalLink,
  Facebook,
  AlertCircle,
  Timer
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const items = await db.getCategory(category);
      setData(items);

      if (category === 'prayer') {
        try {
          const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
          const json = await res.json();
          if (json.code === 200) {
            const t = json.data.timings;
            setData([
              { name: 'ফজর', time: t.Fajr, icon: '🌅' },
              { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
              { name: 'আসর', time: t.Asr, icon: '🌤️' },
              { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
              { name: 'এশা', time: t.Isha, icon: '🌙' },
            ]);
          }
        } catch (e) {
          console.warn("Prayer fetch error", e);
        }
      }
      setLoading(false);
    };
    fetchData();
  }, [category]);

  const runAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক গ্রুপগুলোতে সর্বশেষ আপডেট চেক করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটির বর্তমান অবস্থান ফেসবুকের ট্রেন ট্র্যাকিং গ্রুপগুলো থেকে খুঁজে বের করুন। তথ্যটি কতক্ষণ আগের (Verification Time) এবং বর্তমানে কোন স্টেশনে আছে তা স্পষ্টভাবে জানান। যদি কোনো বিলম্ব (Delay) থাকে তাও উল্লেখ করুন। তথ্যের সূত্র হিসেবে ফেসবুকের লিঙ্কগুলো দিন। বাংলায় উত্তর দিন।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে অফিসার। ফেসবুক গ্রুপ ও সোশ্যাল মিডিয়া থেকে ট্রেনের রিয়েল-টাইম ডাটা এবং তথ্যের সময় (Timestamp) খুঁজে বের করাই আপনার প্রধান কাজ।"
      });

      const sources = response.groundingMetadata?.groundingChunks || [];

      setAiInference({
        delayMinutes: 0,
        confidence: 0.95,
        reason: response.text || 'তথ্য সংগ্রহ করা সম্ভব হয়নি।',
        isAI: true,
        sources: sources
      });
    } catch (e) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: 'দুঃখিত, এই মুহূর্তে ফেসবুক বা ইন্টারনেটে ট্রেনের লাইভ তথ্য পাওয়া যায়নি।', 
        isAI: false, 
        sources: [] 
      });
    } finally {
      setIsInferring(false);
    }
  };

  const renderRouteMap = (routeStr: string) => {
    const stations = routeStr.split(',').map(s => s.trim());
    return (
      <div className="mt-8 relative">
        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 px-2 flex items-center gap-2">
