                 <p className="text-sm font-bold dark:text-slate-200 leading-relaxed">
                   {isInferring ? 'ফেসবুকের লোকাল গ্রুপগুলো থেকে তথ্যের সঠিকতা যাচাই করা হচ্ছে...' : aiInference.reason}
                 </p>
