import { RAJBARI_DATA } from './constants.tsx';
import { GoogleGenAI } from "@google/genai";

// Ensure process.env is safely accessed
const getApiKey = () => {
  // Directly try to access process.env.API_KEY which is expected from the environment
  const key = typeof process !== 'undefined' ? process.env.API_KEY : (window as any).process?.env?.API_KEY;
  return key || "";
};

export const db = {
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
  }) => {
    const apiKey = getApiKey();

    if (!apiKey) {
      throw new Error("API Key Configuration Error: 'API_KEY' এনভায়রনমেন্ট ভেরিয়েবলটি সেট করা নেই।");
    }

    const ai = new GoogleGenAI({ apiKey: apiKey });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: params.contents,
      config: {
        systemInstruction: params.systemInstruction || `আপনি রাজবাড়ী জেলার একজন স্মার্ট অ্যাসিস্ট্যান্ট। তথ্য প্রদানে সত্যতা বজায় রাখুন এবং সর্বদা বাংলায় উত্তর দিন।`,
        tools: params.tools || [{ googleSearch: {} }],
        responseSchema: params.responseSchema,
        responseMimeType: params.responseMimeType,
        temperature: 0.1,
        topP: 0.95
      }
    });

    return {
      text: response.text || "",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
    };
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

