  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  ExternalLink,
  Facebook,
  AlertCircle,
  Timer,
  TrendingUp,
  TrendingDown,
  ArrowRight,
  Briefcase,
  Megaphone,
  Calendar,
  DollarSign,
  Search
} from 'lucide-react';
import { Category, Train, AIInference, MarketItem, Notice, Job } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else if (category === 'notices' || category === 'jobs') {
        await runDynamicContentAI(category);
      } else {
        const items = await db.getCategory(category);
        setData(items);

        if (category === 'prayer') {
          const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
          const json = await res.json();
          if (json.code === 200) {
            const t = json.data.timings;
            setData([
              { name: 'ফজর', time: t.Fajr, icon: '🌅' },
              { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
              { name: 'আসর', time: t.Asr, icon: '🌤️' },
              { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
              { name: 'এশা', time: t.Isha, icon: '🌙' },
            ]);
          }
        }
      }
    } catch (e: any) {
      console.error(e);
      setError(e.message || "তথ্য লোড করতে সমস্যা হয়েছে।");
      // Fallback to static data
      const items = await db.getCategory(category);
      setData(items);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [category]);

  const runMarketAI = async () => {
    const prompt = `আজকের তারিখ ${new Date().toLocaleDateString('bn-BD')}। রাজবাড়ী জেলার স্থানীয় বাজার (যেমন: বড় বাজার, মুরগি ফার্ম মোড়) থেকে নিত্যপণ্যের (চাল, ডাল, পেঁয়াজ, আলু, চিনি, সয়াবিন তেল, ব্রয়লার মুরগি, ডিম) বর্তমান খুচরা দাম খুঁজে বের করুন। তথ্যটি JSON Array ফরম্যাটে দিন। Schema: Array of { name: string, unit: string, priceRange: string, trend: "up" | "down" | "stable" }`;

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার বাজার বিশ্লেষণকারী। সঠিক ডাটা দিন এবং শুধুমাত্র JSON প্রদান করুন।",
      responseMimeType: "application/json"
    });

    const parsedData = JSON.parse(response.text);
    setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
  };

  const runDynamicContentAI = async (cat: string) => {
    const prompt = cat === 'jobs' 
      ? "রাজবাড়ী জেলা প্রশাসনের ওয়েবসাইট (rajbari.gov.bd), স্থানীয় পত্রিকা ও ফেসবুক গ্রুপ থেকে একদম নতুন চাকরির নিয়োগ বিজ্ঞপ্তিগুলো (সরকারি ও বেসরকারি) খুঁজে বের করুন। JSON Array ফরম্যাটে দিন। Schema: Array of { title: string, org: string, deadline: string, link: string, type: string }"
      : "রাজবাড়ী জেলা প্রশাসনের আজকের জরুরি নোটিশ বা আবহাওয়া/পরিবহন সংক্রান্ত ঘোষণাগুলো খুঁজে বের করুন। JSON Array ফরম্যাটে দিন। Schema: Array of { title: string, date: string, summary: string, priority: 'high' | 'normal' }";

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: `আপনি রাজবাড়ী জেলার ডিজিটাল ইনফরমেশন অফিসার। সাম্প্রতিক ${cat === 'jobs' ? 'চাকরি' : 'নোটিশ'} খুঁজে বের করুন এবং শুধুমাত্র JSON প্রদান করুন।`,
      responseMimeType: "application/json"
    });

    const parsedData = JSON.parse(response.text);
    setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `${cat}-${idx}` })));
  };

  const runTrainAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক আপডেট চেক করা হচ্ছে...', isAI: true, sources: [] });
    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটি বর্তমানে কোথায় আছে তা রাজবাড়ী রেলওয়ে সেবা ফেসবুক গ্রুপ থেকে খুঁজে বের করুন। তথ্যটি কতক্ষণ আগের এবং বর্তমানে কোন স্টেশনে আছে তা বাংলায় জানান।`;
      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে অফিসার। ফেসবুক গ্রুপ থেকে ট্রেনের লাইভ লোকেশন খুঁজে বের করুন।"
      });
      setAiInference({ delayMinutes: 0, confidence: 0.95, reason: response.text || 'তথ্য পাওয়া যায়নি।', isAI: true, sources: response.groundingMetadata?.groundingChunks || [] });
    } catch (e: any) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: e.message || 'লাইভ তথ্য পাওয়া যায়নি।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const renderMarketItem = (item: MarketItem) => (
    <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm">
      <div className="flex items-center gap-4">
        <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600">
          <DollarSign className="w-7 h-7" />
        </div>
        <div>
          <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p>
        </div>
      </div>
      <div className="text-right">
        <div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div>
        <div className={`flex items-center justify-end gap-1 text-[9px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : item.trend === 'down' ? 'text-emerald-500' : 'text-slate-400'}`}>
          {item.trend === 'up' ? <TrendingUp className="w-3 h-3" /> : item.trend === 'down' ? <TrendingDown className="w-3 h-3" /> : <ClockIcon className="w-3 h-3" />}
          {item.trend === 'up' ? 'উর্ধ্বমুখী' : item.trend === 'down' ? 'হ্রাস' : 'স্থির'}
        </div>
      </div>
    </div>
  );

  const renderNoticeItem = (notice: Notice) => (
    <div key={notice.id} className={`bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border-l-8 ${notice.priority === 'high' ? 'border-l-rose-500' : 'border-l-indigo-500'} border border-slate-100 dark:border-slate-800 shadow-sm`}>
      <div className="flex items-center gap-2 mb-3">
        <Megaphone className="w-4 h-4 text-indigo-600" />
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{notice.date}</span>
      </div>
      <h4 className="font-black text-slate-800 dark:text-white text-lg leading-tight mb-2">{notice.title}</h4>
      <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed">{notice.summary}</p>
    </div>
  );

  const renderJobItem = (job: Job) => (
    <div key={job.id} className="bg-white dark:bg-slate-900 p-6 rounded-[3rem] mb-5 border border-slate-100 dark:border-slate-800 shadow-sm group hover:border-indigo-400 transition-all">
      <div className="flex items-start gap-4 mb-4">
        <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
          <Briefcase className="w-6 h-6" />
        </div>
        <div>
          <h4 className="font-black text-slate-800 dark:text-white text-lg leading-tight mb-1">{job.title}</h4>
          <p className="text-sm text-slate-500 font-bold">{job.org}</p>
        </div>
      </div>
      <div className="flex items-center gap-3 mb-6">
        <div className="flex items-center gap-1.5 bg-slate-50 dark:bg-slate-800 px-4 py-1.5 rounded-full border border-slate-100">
          <Calendar className="w-3.5 h-3.5 text-slate-400" />
          <span className="text-[10px] font-black text-slate-500 uppercase">{job.deadline}</span>
        </div>
        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full border border-indigo-100">{job.type}</span>
      </div>
      <a href={job.link} target="_blank" className="w-full flex items-center justify-center gap-2 bg-slate-900 dark:bg-indigo-600 text-white py-4 rounded-[1.5rem] font-black text-xs uppercase tracking-widest active:scale-95 transition-all">
        আবেদন লিঙ্ক <ExternalLink className="w-4 h-4" />
      </a>
    </div>
  );

  const renderItem = (item: any) => {
    if (category === 'market_price') return renderMarketItem(item);
    if (category === 'notices') return renderNoticeItem(item);
    if (category === 'jobs') return renderJobItem(item);
    if (category === 'trains') {
      return (
        <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="group bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all hover:border-indigo-400">
          <div className="flex items-start justify-between">
            <div className="flex items-center gap-4">
              <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><TrainFront className="w-6 h-6" /></div>
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-indigo-600 uppercase mb-1">প্রস্থান</p>
              <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
            </div>
          </div>
          <div className="flex items-center justify-between pt-4 border-t border-slate-50 dark:border-slate-800/50">
             <div className="flex items-center gap-2 text-slate-400"><History className="w-3.5 h-3.5" /><span className="text-[10px] font-bold">ছুটি: {item.offDay}</span></div>
             <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/30 px-5 py-2 rounded-full"><Radar className="w-3 h-3 text-indigo-500 animate-pulse" /><span className="text-[9px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">লাইভ রাডার</span></div>
          </div>
        </div>
      );
    }

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm hover:border-indigo-200 transition-all">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl">{item.icon || <Info className="w-6 h-6 text-indigo-500" />}</div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-sm leading-tight">{item.name || item.title}</h4><p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.mobile || item.address || item.time || item.details}</p></div>
        </div>
        {(item.mobile || item.number) && (
          <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl"><Phone className="w-5 h-5" /></a>
        )}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tighter uppercase leading-none mb-1">
            {category === 'emergency' ? 'জরুরি সেবা' : category === 'trains' ? 'রেলওয়ে আপডেট' : category === 'market_price' ? 'বাজারদর (AI)' : category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em] flex items-center gap-2">
            {(category === 'market_price' || category === 'jobs') && <Sparkles className="w-3 h-3 text-amber-500" />}
            Rajbari Smart Portal
          </p>
        </div>
        <button onClick={fetchData} className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-indigo-600">
           <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <Loader2 className="w-14 h-14 animate-spin text-indigo-600" />
          <p className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">রাজবাড়ী সার্ভার স্ক্যানিং...</p>
        </div>
      ) : error ? (
        <div className="bg-rose-50 dark:bg-rose-950/20 p-8 rounded-[3rem] border border-rose-200 dark:border-rose-900/50 text-center">
           <AlertCircle className="w-12 h-12 text-rose-500 mx-auto mb-4" />
           <h4 className="font-bold text-rose-700 dark:text-rose-400 mb-2">এপিআই এরর দেখা দিয়েছে</h4>
           <p className="text-sm text-rose-600 dark:text-rose-500 mb-6">{error}</p>
           <p className="text-[10px] text-slate-400 uppercase tracking-widest leading-relaxed">Vercel Settings-এ গিয়ে API_KEY এনভায়রনমেন্ট ভেরিয়েবল চেক করুন।</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? (
            data.map(renderItem)
          ) : (
            <div className="text-center py-20 bg-white dark:bg-slate-900 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
               <Search className="w-12 h-12 text-slate-200 mx-auto mb-4" />
               <p className="text-slate-400 font-bold">কোনো নতুন তথ্য পাওয়া যায়নি।</p>
            </div>
          )}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/95 backdrop-blur-xl flex items-end md:items-center justify-center p-0 md:p-6 animate-in fade-in duration-300">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-t-[3.5rem] md:rounded-[3.5rem] overflow-hidden shadow-2xl relative max-h-[92vh] flex flex-col">
            <button onClick={() => setSelectedTrain(null)} className="absolute top-8 right-8 p-3 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-500 z-50 hover:bg-rose-50 transition-all"><X className="w-6 h-6" /></button>
            <div className="p-8 pb-4 overflow-y-auto no-scrollbar">
              <div className="flex items-center gap-4 mb-8">
                <div className="p-4 bg-indigo-600 text-white rounded-[1.8rem] shadow-xl animate-swing"><TrainFront className="w-8 h-8" /></div>
                <div><h3 className="text-2xl font-black dark:text-white leading-tight">{selectedTrain.name}</h3><p className="text-indigo-500 font-black text-[10px] uppercase tracking-[0.3em]">{selectedTrain.route}</p></div>
              </div>
              <div className="p-6 bg-indigo-50 dark:bg-indigo-950/30 rounded-[2.2rem] border border-indigo-100 dark:border-indigo-900/50 shadow-sm relative overflow-hidden mb-10">
                 <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                      <Facebook className="w-4 h-4 text-blue-600 fill-blue-600" />
                      <h4 className="text-[11px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">লাইভ রিপোর্ট</h4>
                    </div>
                    {!isInferring && <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 px-3 py-1 rounded-full border border-indigo-100"><Timer className="w-3 h-3 text-emerald-500" /><span className="text-[9px] font-black text-emerald-600 uppercase">Verified</span></div>}
                 </div>
                 <p className="text-sm font-bold dark:text-slate-200 leading-relaxed">{isInferring ? 'ফেসবুক থেকে তথ্যের সঠিকতা যাচাই করা হচ্ছে...' : aiInference.reason}</p>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, Trash2, AlertCircle, RefreshCcw, ShieldCheck, Globe, Info } from 'lucide-react';
import { db } from '../db';

const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার দায়িত্ব ও বৈশিষ্ট্য:
১. রাজবাড়ী জেলা সম্পর্কে সকল তথ্য প্রদান করা।
২. ভাষা: সর্বদা বাংলা ব্যবহার করবেন।
৩. টোন: বিনয়ী ও সম্মানজনক।
৪. ডেভেলপার: Sovrab Roy।
৫. গুগল সার্চ ব্যবহার করে তথ্য দিন এবং তথ্যের সূত্র উল্লেখ করুন।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  errorType?: 'api_key' | 'network' | 'unknown';
  sources?: any[];
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। রাজবাড়ী সম্পর্কে জানতে আপনি আমাকে যেকোনো প্রশ্ন করতে পারেন।' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      const chatHistory = messages
        .filter(m => !m.isError)
        .map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }));

      const data = await db.callAI({
        contents: [...chatHistory, { role: 'user', parts: [{ text: userMessage }] }],
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }]
      });

      const responseText = data.text || "দুঃখিত, আমি এই মুহূর্তে উত্তর দিতে পারছি না।";
      const sources = data.groundingMetadata?.groundingChunks || [];

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: responseText,
        sources: sources
      }]);
    } catch (error: any) {
      console.error("AI Error:", error);
      let errorMsg = "সার্ভারের সাথে সংযোগ করা যাচ্ছে না।";
      let type: 'api_key' | 'network' | 'unknown' = 'unknown';

      if (error.message?.includes('API Key')) {
        errorMsg = "এপিআই কী (API Key) কনফিগার করা হয়নি। আপনার হোস্টিং সেটিংস চেক করুন।";
        type = 'api_key';
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: errorMsg, 
        isError: true, 
        errorType: type 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none">রাজবাড়ী স্মার্ট সাপোর্ট</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600">
                <ShieldCheck className="w-2.5 h-2.5" />
                Gemini 3 Active
              </div>
            </div>
          </div>
        </div>
        <button onClick={() => setMessages([{ role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। আপনাকে কিভাবে সাহায্য করতে পারি?' }])} className="p-3 text-slate-400 hover:text-rose-500 rounded-xl">
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`p-4 rounded-3xl text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600 shadow-indigo-100' 
                  : msg.isError 
                    ? 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-400 border-rose-200 dark:border-rose-900/50 rounded-tl-none'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
                  {msg.isError && <AlertCircle className="w-4 h-4 mb-2 inline-block mr-1" />}
                  {msg.text}

                  {msg.isError && msg.errorType === 'api_key' && (
                    <div className="mt-3 p-3 bg-white/50 dark:bg-slate-800/50 rounded-xl border border-rose-200/50 flex items-start gap-2">
                      <Info className="w-4 h-4 text-rose-500 mt-0.5 shrink-0" />
                      <p className="text-[10px] text-slate-500 font-bold leading-tight">Vercel ড্যাশবোর্ড থেকে 'Settings' > 'Environment Variables'-এ গিয়ে API_KEY ভ্যালুটি যোগ করুন।</p>
                    </div>
                  )}

                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-4 pt-3 border-t border-slate-200/50 dark:border-slate-700/50">
                      <p className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-2">তথ্যসূত্র (Verified Source):</p>
                      <div className="flex flex-wrap gap-2">
                        {msg.sources.map((chunk: any, sidx: number) => (
                          chunk.web && (
                            <a 
                              key={sidx} 
                              href={chunk.web.uri} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="flex items-center gap-1.5 text-[9px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2.5 py-1 rounded-lg border border-indigo-100 dark:border-indigo-800/50"
                            >
                              <Globe className="w-2.5 h-2.5" /> Source {sidx+1}
                            </a>
                          )
                        ))}
                      </div>
                    </div>
                  )}
                </div>
                {msg.isError && (
                  <button onClick={() => handleSend([...messages].reverse().find(m => m.role === 'user')?.text)} className="flex items-center gap-2 text-[10px] font-black text-indigo-600 bg-white dark:bg-slate-900 px-4 py-2 rounded-full shadow-sm border border-indigo-50 dark:border-indigo-900/50 self-start">
                    <RefreshCcw className="w-3 h-3" /> পুনরায় চেষ্টা
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-white dark:bg-slate-800 flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800"><Bot className="w-4 h-4" /></div>
            <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-6 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800">
        <div className="flex gap-3 bg-slate-50 dark:bg-slate-900 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-800 focus-within:border-indigo-400 transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="রাজবাড়ী সম্পর্কে জিজ্ঞাসা করুন..." 
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 text-slate-800 dark:text-white"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isTyping}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
              !input.trim() || isTyping ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white shadow-lg'
            }`}
          >
            {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  ExternalLink,
  Facebook,
  AlertCircle,
  Timer,
  TrendingUp,
  TrendingDown,
  ArrowRight,
  Briefcase,
  Megaphone,
  Calendar,
  DollarSign,
  Search,
  // Added RefreshCcw to fix the reference error
  RefreshCcw
} from 'lucide-react';
import { Category, Train, AIInference, MarketItem, Notice, Job } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else if (category === 'notices' || category === 'jobs') {
        await runDynamicContentAI(category);
      } else {
        const items = await db.getCategory(category);
        setData(items);

        if (category === 'prayer') {
          const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
          const json = await res.json();
          if (json.code === 200) {
            const t = json.data.timings;
            setData([
              { name: 'ফজর', time: t.Fajr, icon: '🌅' },
              { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
              { name: 'আসর', time: t.Asr, icon: '🌤️' },
              { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
              { name: 'এশা', time: t.Isha, icon: '🌙' },
            ]);
          }
        }
      }
    } catch (e: any) {
      console.error(e);
      setError(e.message || "তথ্য লোড করতে সমস্যা হয়েছে।");
      // Fallback to static data
      const items = await db.getCategory(category);
      setData(items);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [category]);

  const runMarketAI = async () => {
    const prompt = `আজকের তারিখ ${new Date().toLocaleDateString('bn-BD')}। রাজবাড়ী জেলার স্থানীয় বাজার (যেমন: বড় বাজার, মুরগি ফার্ম মোড়) থেকে নিত্যপণ্যের (চাল, ডাল, পেঁয়াজ, আলু, চিনি, সয়াবিন তেল, ব্রয়লার মুরগি, ডিম) বর্তমান খুচরা দাম খুঁজে বের করুন। তথ্যটি JSON Array ফরম্যাটে দিন। Schema: Array of { name: string, unit: string, priceRange: string, trend: "up" | "down" | "stable" }`;

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার বাজার বিশ্লেষণকারী। সঠিক ডাটা দিন এবং শুধুমাত্র JSON প্রদান করুন।",
      responseMimeType: "application/json"
    });

    const parsedData = JSON.parse(response.text);
    setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
  };

  const runDynamicContentAI = async (cat: string) => {
    const prompt = cat === 'jobs' 
      ? "রাজবাড়ী জেলা প্রশাসনের ওয়েবসাইট (rajbari.gov.bd), স্থানীয় পত্রিকা ও ফেসবুক গ্রুপ থেকে একদম নতুন চাকরির নিয়োগ বিজ্ঞপ্তিগুলো (সরকারি ও বেসরকারি) খুঁজে বের করুন। JSON Array ফরম্যাটে দিন। Schema: Array of { title: string, org: string, deadline: string, link: string, type: string }"
      : "রাজবাড়ী জেলা প্রশাসনের আজকের জরুরি নোটিশ বা আবহাওয়া/পরিবহন সংক্রান্ত ঘোষণাগুলো খুঁজে বের করুন। JSON Array ফরম্যাটে দিন। Schema: Array of { title: string, date: string, summary: string, priority: 'high' | 'normal' }";

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: `আপনি রাজবাড়ী জেলার ডিজিটাল ইনফরমেশন অফিসার। সাম্প্রতিক ${cat === 'jobs' ? 'চাকরি' : 'নোটিশ'} খুঁজে বের করুন এবং শুধুমাত্র JSON প্রদান করুন।`,
      responseMimeType: "application/json"
    });

    const parsedData = JSON.parse(response.text);
    setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `${cat}-${idx}` })));
  };

  const runTrainAIInference = async (train: Train) => {
    setIsInferring(true);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক আপডেট চেক করা হচ্ছে...', isAI: true, sources: [] });
    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটি বর্তমানে কোথায় আছে তা রাজবাড়ী রেলওয়ে সেবা ফেসবুক গ্রুপ থেকে খুঁজে বের করুন। তথ্যটি কতক্ষণ আগের এবং বর্তমানে কোন স্টেশনে আছে তা বাংলায় জানান।`;
      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে অফিসার। ফেসবুক গ্রুপ থেকে ট্রেনের লাইভ লোকেশন খুঁজে বের করুন।"
      });
      setAiInference({ delayMinutes: 0, confidence: 0.95, reason: response.text || 'তথ্য পাওয়া যায়নি।', isAI: true, sources: response.groundingMetadata?.groundingChunks || [] });
    } catch (e: any) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: e.message || 'লাইভ তথ্য পাওয়া যায়নি।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const renderMarketItem = (item: MarketItem) => (
    <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm">
      <div className="flex items-center gap-4">
        <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600">
          <DollarSign className="w-7 h-7" />
        </div>
        <div>
          <h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p>
        </div>
      </div>
      <div className="text-right">
        <div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div>
        <div className={`flex items-center justify-end gap-1 text-[9px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : item.trend === 'down' ? 'text-emerald-500' : 'text-slate-400'}`}>
          {item.trend === 'up' ? <TrendingUp className="w-3 h-3" /> : item.trend === 'down' ? <TrendingDown className="w-3 h-3" /> : <ClockIcon className="w-3 h-3" />}
          {item.trend === 'up' ? 'উর্ধ্বমুখী' : item.trend === 'down' ? 'হ্রাস' : 'স্থির'}
        </div>
      </div>
    </div>
  );

  const renderNoticeItem = (notice: Notice) => (
    <div key={notice.id} className={`bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border-l-8 ${notice.priority === 'high' ? 'border-l-rose-500' : 'border-l-indigo-500'} border border-slate-100 dark:border-slate-800 shadow-sm`}>
      <div className="flex items-center gap-2 mb-3">
        <Megaphone className="w-4 h-4 text-indigo-600" />
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{notice.date}</span>
      </div>
      <h4 className="font-black text-slate-800 dark:text-white text-lg leading-tight mb-2">{notice.title}</h4>
      <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed">{notice.summary}</p>
    </div>
  );

  const renderJobItem = (job: Job) => (
    <div key={job.id} className="bg-white dark:bg-slate-900 p-6 rounded-[3rem] mb-5 border border-slate-100 dark:border-slate-800 shadow-sm group hover:border-indigo-400 transition-all">
      <div className="flex items-start gap-4 mb-4">
        <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
          <Briefcase className="w-6 h-6" />
        </div>
        <div>
          <h4 className="font-black text-slate-800 dark:text-white text-lg leading-tight mb-1">{job.title}</h4>
          <p className="text-sm text-slate-500 font-bold">{job.org}</p>
        </div>
      </div>
      <div className="flex items-center gap-3 mb-6">
        <div className="flex items-center gap-1.5 bg-slate-50 dark:bg-slate-800 px-4 py-1.5 rounded-full border border-slate-100">
          <Calendar className="w-3.5 h-3.5 text-slate-400" />
          <span className="text-[10px] font-black text-slate-500 uppercase">{job.deadline}</span>
        </div>
        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full border border-indigo-100">{job.type}</span>
      </div>
      <a href={job.link} target="_blank" className="w-full flex items-center justify-center gap-2 bg-slate-900 dark:bg-indigo-600 text-white py-4 rounded-[1.5rem] font-black text-xs uppercase tracking-widest active:scale-95 transition-all">
        আবেদন লিঙ্ক <ExternalLink className="w-4 h-4" />
      </a>
    </div>
  );

  const renderItem = (item: any) => {
    if (category === 'market_price') return renderMarketItem(item);
    if (category === 'notices') return renderNoticeItem(item);
    if (category === 'jobs') return renderJobItem(item);
    if (category === 'trains') {
      return (
        <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="group bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all hover:border-indigo-400">
          <div className="flex items-start justify-between">
            <div className="flex items-center gap-4">
              <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all"><TrainFront className="w-6 h-6" /></div>
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-indigo-600 uppercase mb-1">প্রস্থান</p>
              <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
            </div>
          </div>
          <div className="flex items-center justify-between pt-4 border-t border-slate-50 dark:border-slate-800/50">
             <div className="flex items-center gap-2 text-slate-400"><History className="w-3.5 h-3.5" /><span className="text-[10px] font-bold">ছুটি: {item.offDay}</span></div>
             <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/30 px-5 py-2 rounded-full"><Radar className="w-3 h-3 text-indigo-500 animate-pulse" /><span className="text-[9px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">লাইভ রাডার</span></div>
          </div>
        </div>
      );
    }

    return (
