            <div className="p-8 pb-4 overflow-y-auto no-scrollbar">
              <div className="flex items-center gap-4 mb-8">
                <div className="p-4 bg-indigo-600 text-white rounded-[1.8rem] shadow-xl animate-swing"><TrainFront className="w-8 h-8" /></div>
                <div><h3 className="text-2xl font-black dark:text-white leading-tight">{selectedTrain.name}</h3><p className="text-indigo-500 font-black text-[10px] uppercase tracking-[0.3em]">{selectedTrain.route}</p></div>
              </div>

              {/* LIVE REPORT SECTION */}
              <div className="p-6 bg-indigo-50 dark:bg-indigo-950/30 rounded-[2.2rem] border border-indigo-100 dark:border-indigo-900/50 shadow-sm relative overflow-hidden mb-6">
                 <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                      <Facebook className="w-4 h-4 text-blue-600 fill-blue-600" />
                      <h4 className="text-[11px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">লাইভ রিপোর্ট</h4>
                    </div>
                    {!isInferring && <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 px-3 py-1 rounded-full border border-indigo-100"><Timer className="w-3 h-3 text-emerald-500" /><span className="text-[9px] font-black text-emerald-600 uppercase">Verified</span></div>}
                 </div>
                 <p className="text-sm font-bold dark:text-slate-200 leading-relaxed">{isInferring ? 'ফেসবুক থেকে তথ্য যাচাই করা হচ্ছে...' : aiInference.reason}</p>
                 {currentStation && (
                    <div className="mt-4 flex items-center gap-2 bg-emerald-100 dark:bg-emerald-950/50 px-4 py-2 rounded-xl border border-emerald-200">
                      <Navigation className="w-4 h-4 text-emerald-600" />
                      <p className="text-xs font-black text-emerald-700 dark:text-emerald-400">ট্রেনটি এখন: {currentStation}</p>
                    </div>
                 )}
              </div>

              {/* DETAILED ROUTE SECTION */}
              <div className="bg-white dark:bg-slate-800/50 rounded-[2.5rem] p-6 border border-slate-100 dark:border-slate-800 shadow-sm mb-10">
                 <div className="flex items-center gap-3 mb-6">
                    <div className="p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl">
                       <Milestone className="w-5 h-5 text-slate-500" />
                    </div>
                    <div>
                       <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">রুট ডিটেইলস</h4>
                       <p className="text-xs font-black dark:text-white uppercase tracking-tighter">স্টেশন সমূহের তালিকা</p>
                    </div>
                 </div>

                 <div className="relative pl-6 space-y-8 before:content-[''] before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-0.5 before:bg-slate-200 dark:before:bg-slate-700">
                    {selectedTrain.detailedRoute.split(',').map((station, sIdx, arr) => {
                      const sName = station.trim();
                      const isCurrent = currentStation?.includes(sName) || sName.includes(currentStation || "NONE");
                      return (
                        <div key={sIdx} className="relative flex items-center justify-between group">
                          <div className="flex items-center gap-4">
                            <div className={`absolute -left-[21px] w-3 h-3 rounded-full border-2 border-white dark:border-slate-900 z-10 transition-all ${
                              isCurrent ? 'bg-emerald-500 scale-150 shadow-[0_0_15px_rgba(16,185,129,0.8)]' : sIdx === 0 ? 'bg-indigo-600 scale-125' : sIdx === arr.length - 1 ? 'bg-rose-500 scale-125' : 'bg-slate-400'
                            }`}></div>
                            <span className={`text-sm font-bold transition-all ${isCurrent ? 'text-emerald-600 dark:text-emerald-400 text-lg scale-110' : sIdx === 0 || sIdx === arr.length - 1 ? 'text-slate-800 dark:text-white' : 'text-slate-500'}`}>
                              {sName}
                            </span>
                          </div>

                          {isCurrent && (
                            <div className="flex items-center gap-2 animate-bounce">
                               <div className="relative">
                                 <div className="absolute -inset-2 bg-emerald-400/20 rounded-full animate-ping"></div>
                                 <TrainFront className="w-6 h-6 text-emerald-600" />
                               </div>
                               <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest bg-emerald-50 px-2 py-1 rounded-md border border-emerald-100">Live</span>
                            </div>
                          )}
                        </div>
                      );
                    })}
                 </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import { RAJBARI_DATA } from './constants.tsx';
import { GoogleGenAI } from "@google/genai";

export const db = {
  // এআই রেসপন্স থেকে টেক্সট বাদ দিয়ে শুধু JSON অংশটুকু খুঁজে বের করার ফাংশন
  extractJSON: (text: string) => {
    try {
      // রিকোয়েস্টের সাথে আসা যেকোনো অতিরিক্ত লেখা বা মার্কডাউন ফিল্টার করে
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("Critical JSON Parsing Error:", e);
      return null;
    }
  },

  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
    model?: string;
  }) => {
    // সরাসরি process.env.API_KEY ব্যবহার, যা Vercel এনভায়রনমেন্ট থেকে আসবে
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: params.model || 'gemini-3-flash-preview', 
      contents: params.contents,
      config: {
        systemInstruction: params.systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। তথ্য প্রদানে সত্যতা বজায় রাখুন এবং সর্বদা বাংলায় উত্তর দিন।`,
        tools: params.tools || [{ googleSearch: {} }],
        responseSchema: params.responseSchema,
        responseMimeType: params.responseMimeType,
        temperature: 0.1,
      }
    });

    return {
      text: response.text || "",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
    };
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  ExternalLink,
  Facebook,
  AlertCircle,
  Timer,
  TrendingUp,
  TrendingDown,
  ArrowRight,
  Briefcase,
  Megaphone,
  Calendar,
  DollarSign,
  Search,
  RefreshCcw,
  Navigation,
  Milestone
} from 'lucide-react';
import { Category, Train, AIInference, MarketItem, Notice, Job } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else if (category === 'notices' || category === 'jobs') {
        await runDynamicContentAI(category);
      } else {
        const items = await db.getCategory(category);
        setData(items);

        if (category === 'prayer') {
          const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
          const json = await res.json();
          if (json.code === 200) {
            const t = json.data.timings;
            setData([
              { name: 'ফজর', time: t.Fajr, icon: '🌅' },
              { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
              { name: 'আসর', time: t.Asr, icon: '🌤️' },
              { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
              { name: 'এশা', time: t.Isha, icon: '🌙' },
            ]);
          }
        }
      }
    } catch (e: any) {
      console.error("Fetch Error:", e);
      // Fallback: এরর হলে অটোমেটিক লোকাল ডাটা দেখাবে
      const items = await db.getCategory(category);
      setData(items);
      setError("লাইভ আপডেট পেতে সমস্যা হচ্ছে। পুরাতন তথ্য দেখানো হচ্ছে।");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [category]);

  const runMarketAI = async () => {
    const prompt = `আজকের তারিখ ${new Date().toLocaleDateString('bn-BD')}। রাজবাড়ী জেলার বাজার থেকে নিত্যপণ্যের সঠিক দাম খুঁজে বের করুন। JSON Array ফরম্যাটে দিন। Schema: Array of { name: string, unit: string, priceRange: string, trend: "up" | "down" | "stable" }`;

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার বাজার বিশ্লেষণকারী। শুধুমাত্র শুদ্ধ JSON Array দিন।"
    });

    const parsedData = db.extractJSON(response.text);
    if (parsedData) {
      setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
    } else {
      throw new Error("AI data parsing failed");
    }
  };

  const runDynamicContentAI = async (cat: string) => {
    const prompt = cat === 'jobs' 
      ? "রাজবাড়ী জেলার নতুন চাকরির বিজ্ঞপ্তিগুলো খুঁজুন। JSON Array ফরম্যাটে দিন।"
      : "রাজবাড়ী জেলা প্রশাসনের আজকের নোটিশগুলো খুঁজুন। JSON Array ফরম্যাটে দিন।";

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার তথ্য অফিসার। শুধুমাত্র JSON Array প্রদান করুন।"
    });

    const parsedData = db.extractJSON(response.text);
    if (parsedData) {
      setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `${cat}-${idx}` })));
    } else {
      throw new Error("AI content failure");
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক আপডেট চেক করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটির বর্তমান অবস্থান 'রাজবাড়ী রেলওয়ে সেবা' গ্রুপ থেকে খুঁজে বের করুন। 
      ট্রেনটি বর্তমানে কোন স্টেশনে আছে তা নিশ্চিত করুন। উত্তরের শুরুতে অবশ্যই এভাবে লিখুন: [STATION: স্টেশনের নাম]।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে অফিসার।",
        model: 'gemini-3-pro-preview'
      });

      const stationMatch = response.text.match(/\[STATION:\s*(.*?)\]/);
      if (stationMatch && stationMatch[1]) {
        const found = stationMatch[1].trim();
        const routeStations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = routeStations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.95, 
        reason: response.text.replace(/\[STATION:.*?\]/, '').trim() || 'তথ্য পাওয়া যায়নি।', 
        isAI: true, 
        sources: response.groundingMetadata?.groundingChunks || [] 
      });
    } catch (e: any) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'লাইভ তথ্য পাওয়া যায়নি।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const renderItem = (item: any) => {
    if (category === 'market_price') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600"><DollarSign className="w-7 h-7" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase">{item.unit}</p></div>
        </div>
        <div className="text-right">
          <div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div>
          <div className={`flex items-center justify-end gap-1 text-[9px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : 'text-emerald-500'}`}>
