              <div className="bg-white dark:bg-slate-800/50 rounded-[2.5rem] p-6 border border-slate-100 space-y-8 relative pl-6 before:content-[''] before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-0.5 before:bg-slate-200">
