import { RAJBARI_DATA } from './constants.tsx';
import { GoogleGenAI } from "@google/genai";

export const db = {
  /**
   * এআই অনেক সময় উত্তরের সাথে অতিরিক্ত কথা বলে ফেলে।
   * এই ফাংশনটি শুধু প্রয়োজনীয় JSON অংশটুকু খুঁজে বের করবে।
   */
  extractJSON: (text: string) => {
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("JSON Extraction Error:", e);
      return null;
    }
  },

  /**
   * জেমিনি এআই কল করার মেইন ফাংশন।
   * এটি সরাসরি Vercel এর Environment Variable (API_KEY) ব্যবহার করবে।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    responseSchema?: any;
    responseMimeType?: string;
    model?: string;
  }) => {
    // প্রসেস ডট এনভ থেকে এপিআই কী নিচ্ছে যা আপনি ভার্সেলে সেট করবেন
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: params.model || 'gemini-3-flash-preview', 
      contents: params.contents,
      config: {
        systemInstruction: params.systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। তথ্য প্রদানে সত্যতা বজায় রাখুন এবং সর্বদা বাংলায় উত্তর দিন।`,
        tools: params.tools || [{ googleSearch: {} }],
        temperature: 0.1,
      }
    });

    return {
      text: response.text || "",
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
    };
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

