} from 'lucide-react';
import { Category, Train, AIInference, MarketItem, Notice, Job } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else if (category === 'notices' || category === 'jobs') {
        await runDynamicContentAI(category);
      } else {
        const items = await db.getCategory(category);
        setData(items);

        if (category === 'prayer') {
          const res = await fetch('https://api.aladhan.com/v1/timingsByCity?city=Rajbari&country=Bangladesh&method=1');
          const json = await res.json();
          if (json.code === 200) {
            const t = json.data.timings;
            setData([
              { name: 'ফজর', time: t.Fajr, icon: '🌅' },
              { name: 'যোহর', time: t.Dhuhr, icon: '☀️' },
              { name: 'আসর', time: t.Asr, icon: '🌤️' },
              { name: 'মাগরিব', time: t.Maghrib, icon: '🌇' },
              { name: 'এশা', time: t.Isha, icon: '🌙' },
            ]);
          }
        }
      }
    } catch (e: any) {
      console.error("Fetch Error:", e);
      const items = await db.getCategory(category);
      setData(items);
      setError("লাইভ আপডেট পেতে সমস্যা হচ্ছে। পুরাতন তথ্য দেখানো হচ্ছে।");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [category]);

  const runMarketAI = async () => {
    const prompt = `আজকের তারিখ ${new Date().toLocaleDateString('bn-BD')}। রাজবাড়ী জেলার স্থানীয় বাজার থেকে নিত্যপণ্যের (চাল, ডাল, তেল, ডিম, মুরগি) দাম গুগল সার্চ করে বের করুন। উত্তরটি শুধুমাত্র একটি JSON Array ফরম্যাটে দিন।`;

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার বাজার বিশ্লেষণকারী। শুধুমাত্র শুদ্ধ JSON Array দিন।"
    });

    const parsedData = db.extractJSON(response.text);
    if (parsedData) {
      setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
    } else {
      throw new Error("AI data parsing failed");
    }
  };

  const runDynamicContentAI = async (cat: string) => {
    const prompt = cat === 'jobs' 
      ? "রাজবাড়ী জেলার নতুন চাকরির বিজ্ঞপ্তিগুলো খুঁজুন। JSON Array ফরম্যাটে দিন।"
      : "রাজবাড়ী জেলা প্রশাসনের আজকের জরুরি নোটিশগুলো খুঁজুন। JSON Array ফরম্যাটে দিন।";

    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার তথ্য অফিসার। শুধুমাত্র JSON Array প্রদান করুন।"
    });

    const parsedData = db.extractJSON(response.text);
    if (parsedData) {
      setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `${cat}-${idx}` })));
    } else {
      throw new Error("AI content failure");
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'ফেসবুক গ্রুপে আপডেট চেক করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটির বর্তমান অবস্থান 'রাজবাড়ী রেলওয়ে সেবা' ফেসবুক গ্রুপ থেকে খুঁজে বের করুন। 
      ট্রেনটি বর্তমানে ঠিক কোন স্টেশনে দাঁড়িয়ে আছে বা কোন স্টেশন পার হয়েছে তা নিশ্চিত করুন। উত্তরের শুরুতে অবশ্যই এভাবে লিখুন: [STATION: স্টেশনের নাম]। এরপর বিস্তারিত বলুন।`;

      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রেলওয়ে অফিসার। ফেসবুক গ্রুপ থেকে সঠিক ও সর্বশেষ তথ্য সংগ্রহ করুন।",
        model: 'gemini-3-pro-preview'
      });

      const stationMatch = response.text.match(/\[STATION:\s*(.*?)\]/);
      if (stationMatch && stationMatch[1]) {
        const found = stationMatch[1].trim();
        const routeStations = train.detailedRoute.split(',').map(s => s.trim());
        // স্টেশনের নাম মিলছে কিনা তা যাচাই করা
        const bestMatch = routeStations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      } else {
        // ফালব্যাক: টেক্সটের ভেতর থেকে স্টেশনের নাম খোঁজা
        const routeStations = train.detailedRoute.split(',');
        for (const s of routeStations) {
          if (response.text.includes(s.trim())) {
            setCurrentStation(s.trim());
            break;
          }
        }
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.95, 
        reason: response.text.replace(/\[STATION:.*?\]/, '').trim() || 'তথ্য পাওয়া যায়নি।', 
        isAI: true, 
        sources: response.groundingMetadata?.groundingChunks || [] 
      });
    } catch (e: any) {
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'লাইভ তথ্য পাওয়া যায়নি। ইন্টারনাল এরর।', isAI: false, sources: [] });
    } finally { setIsInferring(false); }
  };

  const renderItem = (item: any) => {
    if (category === 'market_price') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm hover:shadow-md transition-shadow">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600"><DollarSign className="w-7 h-7" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p></div>
        </div>
        <div className="text-right">
          <div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div>
          <div className={`flex items-center justify-end gap-1 text-[9px] font-black uppercase ${item.trend === 'up' ? 'text-rose-500' : 'text-emerald-500'}`}>
            {item.trend === 'up' ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
            {item.trend === 'up' ? 'উর্ধ্বমুখী' : 'কমছে'}
          </div>
        </div>
      </div>
    );

    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all hover:border-indigo-400">
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl"><TrainFront className="w-6 h-6" /></div>
            <div><h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p></div>
          </div>
          <div className="text-right"><p className="text-[9px] font-black text-indigo-600 uppercase mb-1">প্রস্থান</p><p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p></div>
        </div>
        <div className="flex items-center justify-between pt-4 border-t border-slate-50 dark:border-slate-800/50">
           <div className="flex items-center gap-2 text-slate-400"><History className="w-3.5 h-3.5" /><span className="text-[10px] font-bold">ছুটি: {item.offDay}</span></div>
           <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/30 px-5 py-2 rounded-full"><Radar className="w-3 h-3 text-indigo-500 animate-pulse" /><span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">লাইভ ট্র্যাকিং</span></div>
        </div>
      </div>
    );

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl">{item.icon || <Info className="w-6 h-6 text-indigo-500" />}</div>
