import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  // শুধুমাত্র POST রিকোয়েস্ট গ্রহণ করবে
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const { contents, systemInstruction, tools, model } = req.body;

  // এনভায়রনমেন্ট ভেরিয়েবল থেকে এপিআই কী যাচাই
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return res.status(500).json({ error: 'API_KEY is not configured in Vercel environment variables.' });
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // মডেল সিলেকশন (Default: Flash for speed)
    const selectedModel = model === 'gemini-3-pro-preview' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

    const response = await ai.models.generateContent({
      model: selectedModel,
      contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। সর্বদা বাংলায় উত্তর দিন।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    // সঠিক ডাটা রিটার্ন করা
    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
    });
  } catch (error) {
    console.error('Gemini Backend Error:', error);
    return res.status(500).json({ 
      error: error.message || 'An error occurred during the AI request.',
      details: error.toString()
    });
  }
}

import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * এআই রেসপন্স থেকে JSON এক্সট্রাক্ট করার জন্য।
   */
  extractJSON: (text: string) => {
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("JSON Parsing Error:", e);
      return null;
    }
  },

  /**
   * ব্যাকএন্ড এন্ডপয়েন্টে রিকোয়েস্ট পাঠানো।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
  }) => {
    try {
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(params),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'AI Request Failed');
      }

      return data;
    } catch (error) {
      console.error("Frontend DB Proxy Error:", error);
      throw error;
    }
  },

  getCategory: async (category: string) => {
    // লোকাল ডাটা রিটার্ন করা
    return (RAJBARI_DATA as any)[category] || [];
  }
};

