import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  // শুধুমাত্র POST রিকোয়েস্ট গ্রহণ করা হবে
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const { contents, systemInstruction, tools, model, responseSchema, responseMimeType } = req.body;

  // Vercel Environment Variable থেকে API_KEY নেওয়া হচ্ছে
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'Backend Configuration Error: API_KEY is missing in Vercel Environment Variables.' 
    });
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // মডেল নির্ধারণ (ট্রেন ট্র্যাকিং এর জন্য Pro এবং সাধারণ কাজের জন্য Flash)
    const selectedModel = model === 'gemini-3-pro-preview' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

    const response = await ai.models.generateContent({
      model: selectedModel,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট। সর্বদা বাংলায় উত্তর দিন।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.1,
        responseSchema: responseSchema,
        responseMimeType: responseMimeType,
      },
    });

    // এআই রেসপন্স পাঠানো
    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
    });
  } catch (error) {
    console.error('Gemini Request Failed:', error);
    return res.status(500).json({ 
      error: 'AI Request Failed',
      details: error.message 
    });
  }
}

import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * এআই রেসপন্স থেকে JSON অংশটুকু নিখুঁতভাবে বের করে।
   */
  extractJSON: (text: string) => {
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("JSON Parsing Error:", e);
      return null;
    }
  },

  /**
   * আমাদের Vercel ব্যাকএন্ড এন্ডপয়েন্টে (/api/ai) রিকোয়েস্ট পাঠায়।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      // জেমিনি ফরম্যাট অনুযায়ী contents প্যারামিটারকে সাজানো (Role Fix)
      const normalizedContents = Array.isArray(params.contents) 
        ? params.contents.map(c => ({
            role: c.role || 'user',
            parts: Array.isArray(c.parts) ? c.parts : [{ text: c.parts || c.text || "" }]
          }))
        : [{ role: 'user', parts: [{ text: params.contents }] }];

      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...params,
          contents: normalizedContents
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.details || data.error || 'Backend Error');
      }

      return data;
    } catch (error) {
      console.error("Frontend to Backend Communication Error:", error);
      throw error;
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

