      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [category]);

  const runMarketAI = async () => {
    const prompt = `আজকের তারিখ ${new Date().toLocaleDateString('bn-BD')}। রাজবাড়ী জেলার স্থানীয় বাজার থেকে নিত্যপণ্যের দাম গুগল সার্চ করে বের করুন। উত্তরটি শুধুমাত্র JSON Array ফরম্যাটে দিন।`;
    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "আপনি রাজবাড়ী জেলার বাজার বিশ্লেষণকারী। শুধুমাত্র শুদ্ধ JSON Array দিন।"
    });
    const parsedData = db.extractJSON(response.text);
    if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
    else throw new Error("Market data parse failed");
  };

  const runDynamicContentAI = async (cat: string) => {
    const prompt = cat === 'jobs' ? "রাজবাড়ী জেলার নতুন চাকরির বিজ্ঞপ্তি খুঁজুন।" : "রাজবাড়ী জেলা প্রশাসনের আজকের জরুরি নোটিশ খুঁজুন।";
    const response = await db.callAI({
      contents: [{ parts: [{ text: prompt }] }],
      systemInstruction: "শুধুমাত্র JSON Array প্রদান করুন।"
    });
    const parsedData = db.extractJSON(response.text);
    if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `${cat}-${idx}` })));
    else throw new Error("Content parse failed");
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'তথ্য যাচাই করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" ট্রেনটির সর্বশেষ বর্তমান অবস্থান (Current Location) গুগল নিউজ এবং ফেসবুক গ্রুপ থেকে খুঁজে বের করুন। ট্রেনটি বর্তমানে কোন স্টেশনে দাঁড়িয়ে আছে বা কোন স্টেশন ছেড়েছে তা নিশ্চিত করুন। উত্তরের শুরুতে অবশ্যই এভাবে লিখুন: [STATION: স্টেশনের নাম]। এরপর বিস্তারিত তথ্য দিন।`;

      const response = await db.callAI({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        systemInstruction: "আপনি রাজবাড়ী রেলওয়ে সেবা থেকে সর্বশেষ লাইভ তথ্য প্রদানকারী অফিসার। নির্ভুল তথ্য দিন।",
        model: 'gemini-3-pro-preview'
      });

      const stationMatch = response.text.match(/\[STATION:\s*(.*?)\]/i);
      if (stationMatch && stationMatch[1]) {
        const found = stationMatch[1].trim();
        const routeStations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = routeStations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      } else {
        // Fallback search in text
        const routeStations = train.detailedRoute.split(',');
        for (const s of routeStations) {
          if (response.text.includes(s.trim())) {
            setCurrentStation(s.trim());
            break;
          }
        }
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.9, 
        reason: response.text.replace(/\[STATION:.*?\]/i, '').trim() || 'কোনো লাইভ রিপোর্ট পাওয়া যায়নি।', 
        isAI: true, 
        sources: response.groundingMetadata?.groundingChunks || [] 
      });
    } catch (e: any) {
      console.error("Train Inference Error:", e);
      setAiInference({ delayMinutes: 0, confidence: 0, reason: 'সার্ভার থেকে তথ্য সংগ্রহ করা সম্ভব হয়নি। পুনরায় চেষ্টা করুন।', isAI: false, sources: [] });
