import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  // CORS এবং Method চেক
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return res.status(500).json({ error: 'API_KEY configuration missing on server.' });
  }

  const { contents, systemInstruction, tools, model, responseSchema, responseMimeType } = req.body;

  try {
    const ai = new GoogleGenAI({ apiKey });

    // ট্রেন ট্র্যাকিং এবং সার্চের জন্য Pro মডেলই সেরা, তাই সেটিই ডিফল্ট রাখা হয়েছে।
    // তবে ব্যবহারকারী চাইলে Flash ব্যবহার করতে পারে।
    const targetModel = model || 'gemini-3-pro-preview';

    const response = await ai.models.generateContent({
      model: targetModel,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলা তথ্য সেবার একজন দক্ষ সহকারী।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.1, // তথ্য নির্ভুল রাখার জন্য কম টেম্পারেচার
        responseSchema: responseSchema,
        responseMimeType: responseMimeType,
      },
    });

    if (!response || !response.text) {
        throw new Error("AI returned an empty response.");
    }

    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
    });
  } catch (error) {
    console.error('Gemini Backend Error:', error);

    // যদি প্রলে সমস্যা হয় (যেমন কোটা শেষ), তবে অটোমেটিক ফ্লাশে ট্রাই করার মেসেজ
    return res.status(500).json({ 
      error: 'AI Request Failed',
      details: error.message,
      suggestion: 'Please try again in a moment or check your API key quota.'
    });
  }
}

import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * টেক্সট থেকে JSON অংশ বের করে।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("JSON Parsing Error:", e);
      return null;
    }
  },

  /**
   * ব্যাকএন্ডে এআই রিকোয়েস্ট পাঠায়।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      // জেমিনি এপিআই-এর জন্য contents-কে সঠিকভাবে সাজানো
      let formattedContents = [];

      if (Array.isArray(params.contents)) {
        formattedContents = params.contents.map(c => ({
          role: c.role || 'user',
          parts: Array.isArray(c.parts) ? c.parts : [{ text: String(c.text || c.parts || "") }]
        }));
      } else {
        formattedContents = [{
          role: 'user',
          parts: [{ text: String(params.contents) }]
        }];
      }

      // /api/ai এন্ডপয়েন্টে কল করা
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...params,
          contents: formattedContents
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.details || data.error || 'Network response was not ok');
      }

      return data;
    } catch (error) {
      console.error("Database Proxy Error:", error);
      throw error;
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

