    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      if (!process.env.API_KEY) {
        console.warn("API_KEY is not defined in environment variables.");
      }

      const modelName = params.model || 'gemini-3-flash-preview';

      // কনটেন্ট ফরম্যাট করা
      const formattedContents = Array.isArray(params.contents) 
        ? params.contents.map(c => ({
            role: c.role || 'user',
            parts: Array.isArray(c.parts) ? c.parts : [{ text: String(c.text || c.parts || "") }]
          }))
        : [{ role: 'user', parts: [{ text: String(params.contents) }] }];

      // জেমিনি জেনারেট কন্টেন্ট কল
      const response = await ai.models.generateContent({
        model: modelName,
        contents: formattedContents,
        config: {
          systemInstruction: params.systemInstruction || "আপনি রাজবাড়ী জেলা তথ্য সেবার একজন দক্ষ সহকারী।",
          tools: params.tools || [{ googleSearch: {} }],
          temperature: 0.1,
          responseMimeType: params.responseMimeType,
          responseSchema: params.responseSchema
        }
      });

      if (!response) {
        throw new Error("AI returned an empty response.");
      }

      return {
        text: response.text,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null
      };
    } catch (error: any) {
      console.error("Gemini Frontend Error:", error);
      throw error;
    }
  },

  getCategory: async (category: string) => {
    // লোকাল কনস্ট্যান্ট থেকে ডাটা রিটার্ন
    return (RAJBARI_DATA as any)[category] || [];
  }
};

