export default CategoryView;

import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * টেক্সট থেকে JSON ডাটা খুঁজে বের করে।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("JSON Parsing Error:", e);
      return null;
    }
  },

  /**
   * Vercel Serverless Function (api/ai.js) কল করার ফাংশন।
   * এটি আপনার API_KEY লুকিয়ে রাখে এবং Vercel-এ সঠিকভাবে কাজ করে।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      // সরাসরি SDK কলের বদলে আমরা আমাদের তৈরি করা API এন্ডপয়েন্টে রিকোয়েস্ট পাঠাবো
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          contents: params.contents,
          systemInstruction: params.systemInstruction,
          tools: params.tools,
          model: params.model,
          responseMimeType: params.responseMimeType,
          responseSchema: params.responseSchema
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || data.details || "AI রিকোয়েস্ট ব্যর্থ হয়েছে।");
      }

      return {
        text: data.text,
        groundingMetadata: data.groundingMetadata || null
      };
    } catch (error: any) {
      console.error("AI Bridge Error:", error);
      throw new Error(error.message || "এআই সার্ভারের সাথে যোগাযোগ করা সম্ভব হচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  // শুধুমাত্র POST রিকোয়েস্ট গ্রহণ করবে
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // Vercel Environment Variable থেকে API_KEY নেওয়া
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return res.status(500).json({ error: 'API_KEY is not configured in Vercel environment variables.' });
  }

  const { contents, systemInstruction, tools, model, responseSchema, responseMimeType } = req.body;

  try {
    // প্রতি রিকোয়েস্টে নতুন ইনস্ট্যান্স তৈরি (SDK নিয়ম অনুযায়ী)
    const ai = new GoogleGenAI({ apiKey });
    const targetModel = model || 'gemini-3-flash-preview';

    const response = await ai.models.generateContent({
      model: targetModel,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.1,
        responseSchema: responseSchema,
        responseMimeType: responseMimeType,
      },
    });

    // সঠিক ডাটা রিটার্ন করা
    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
    });
  } catch (error) {
    console.error('Gemini Backend Error:', error);
    return res.status(500).json({ 
      error: 'AI Request Failed',
      details: error.message 
    });
  }
}

