import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const apiKey = (process.env.GEMINI_API_KEY || process.env.API_KEY || "").trim();

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API_KEY missing',
      details: 'Vercel-এর Environment Variables-এ GEMINI_API_KEY সেট করা নেই।' 
    });
  }

  const { contents, systemInstruction, tools, model } = req.body;
  const ai = new GoogleGenAI({ apiKey });
  const targetModel = model || 'gemini-2.5-flash-lite-latest'; // Lite মডেলের কোটা বেশি থাকে

  const generateAIContent = async (useTools) => {
    return await ai.models.generateContent({
      model: targetModel,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন স্মার্ট তথ্য সহায়িকা।",
        tools: useTools ? (tools || [{ googleSearch: {} }]) : [],
        temperature: 0.7,
      },
    });
  };

  try {
    // ১. প্রথমে টুলসহ (গুগল সার্চ) চেষ্টা করা হবে
    let response = await generateAIContent(true);

    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_search'
    });

  } catch (error) {
    console.error('Initial AI Attempt Failed:', error.message);

    // ২. যদি কোটা এরর (429) হয়, তবে টুল ছাড়া (সার্চ ছাড়া) আবার চেষ্টা করবে
    if (error.message.includes("429") || error.message.includes("quota") || error.message.includes("RESOURCE_EXHAUSTED")) {
      try {
        console.log("Retrying without tools due to quota...");
        let fallbackResponse = await generateAIContent(false);

        return res.status(200).json({
          text: fallbackResponse.text + "\n\n(দ্রষ্টব্য: গুগল সার্চ লিমিট শেষ হওয়ায় এটি এআই-এর সংরক্ষিত তথ্য থেকে উত্তর দেওয়া হয়েছে।)",
          groundingMetadata: null,
          mode: 'offline_knowledge'
        });
      } catch (fallbackError) {
        return res.status(500).json({ 
          error: "সব প্রচেষ্টাই ব্যর্থ হয়েছে।",
          details: "আপনার এপিআই কী-র একদম বেসিক লিমিটও শেষ হয়ে গেছে। দয়া করে ৫-১০ মিনিট অপেক্ষা করুন।" 
        });
      }
    }

    return res.status(500).json({ 
      error: 'AI Request Failed',
      details: error.message 
    });
  }
}

