import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
      }
      return null;
    } catch (e) {
      console.error("JSON Parsing Error:", e);
      return null;
    }
  },

  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          contents: params.contents,
          systemInstruction: params.systemInstruction,
          tools: params.tools,
          model: params.model,
          responseMimeType: params.responseMimeType,
          responseSchema: params.responseSchema
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        // যদি details থাকে তবে সেটিই দেখানো হবে
        const errorMsg = data.details || data.error || "AI রিকোয়েস্ট ব্যর্থ হয়েছে।";
        throw new Error(errorMsg);
      }

      // Fix: Include 'mode' in the return object to resolve the TypeScript error in AIChat.tsx
      return {
        text: data.text || "",
        groundingMetadata: data.groundingMetadata || null,
        mode: data.mode || null
      };
    } catch (error: any) {
      console.error("AI Bridge Error:", error);
      throw new Error(error.message || "এআই সার্ভারের সাথে যোগাযোগ করা সম্ভব হচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import 'dotenv/config';
import express from 'express';
import cors from 'cors';
import path from 'path';
import { fileURLToPath } from 'url';
import { GoogleGenAI } from '@google/genai';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();
const port = process.env.PORT || 3001;

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'dist')));

app.post('/api/ai', async (req, res) => {
    // Fix: Extracted additional parameters from request body for better control
    const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
    // Fix: Always obtain API key from process.env.API_KEY per guidelines
    const apiKey = process.env.API_KEY;

    if (!apiKey) {
        return res.status(500).json({ error: "Server Configuration Error: API_KEY is missing." });
    }

    try {
        const ai = new GoogleGenAI({ apiKey: apiKey });
        // Fix: Use gemini-3-flash-preview by default for text tasks and forward response configuration
        const response = await ai.models.generateContent({
            model: model || 'gemini-3-flash-preview',
            contents: contents,
            config: {
                systemInstruction: systemInstruction || `আপনি রাজবাড়ী জেলার একজন ভার্চুয়াল অ্যাসিস্ট্যান্ট।`,
                tools: tools || [{ googleSearch: {} }],
                temperature: 0.1,
                responseMimeType: responseMimeType,
                responseSchema: responseSchema
            }
        });

        // Fix: Include mode to match frontend Message interface expectations
        res.json({
            text: response.text || "",
            groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
            mode: 'live_search'
        });
    } catch (error) {
        console.error("Gemini API Error:", error.message);
        let msg = error.message;
        if (msg.includes("429") || msg.includes("quota")) {
            msg = "আপনার API Key-এর ফ্রি লিমিট শেষ। কিছুক্ষণ অপেক্ষা করুন।";
        }
        res.status(500).json({ error: msg });
    }
});

app.get('*', (req, res) => {
    res.sendFile(path.join(__dirname, 'dist', 'index.html'));
});

app.listen(port, () => console.log(`Rajbari Smart Server active on port ${port}`));

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // Fix: Exclusively use process.env.API_KEY
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API_KEY missing',
      details: 'Vercel-এর Environment Variables-এ API_KEY সেট করা নেই।' 
    });
  }

  // Fix: Extract JSON config and model from body
  const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
  const ai = new GoogleGenAI({ apiKey });
  // Fix: Default to gemini-3-flash-preview for general text tasks per guidelines
  const targetModel = model || 'gemini-3-flash-preview';

  const generateAIContent = async (useTools) => {
    return await ai.models.generateContent({
      model: targetModel,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন স্মার্ট তথ্য সহায়িকা।",
        tools: useTools ? (tools || [{ googleSearch: {} }]) : [],
        temperature: 0.7,
        // Fix: Forward structured output configuration
        responseMimeType: responseMimeType,
        responseSchema: responseSchema
      },
    });
  };

  try {
    // ১. প্রথমে টুলসহ (গুগল সার্চ) চেষ্টা করা হবে
    let response = await generateAIContent(true);

    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_search'
    });

  } catch (error) {
    console.error('Initial AI Attempt Failed:', error.message);

    // ২. যদি কোটা এরর (429) হয়, তবে টুল ছাড়া (সার্চ ছাড়া) আবার চেষ্টা করবে
    if (error.message.includes("429") || error.message.includes("quota") || error.message.includes("RESOURCE_EXHAUSTED")) {
      try {
        console.log("Retrying without tools due to quota...");
        let fallbackResponse = await generateAIContent(false);

        return res.status(200).json({
          text: fallbackResponse.text + "\n\n(দ্রষ্টব্য: গুগল সার্চ লিমিট শেষ হওয়ায় এটি এআই-এর সংরক্ষিত তথ্য থেকে উত্তর দেওয়া হয়েছে।)",
          groundingMetadata: null,
          mode: 'offline_knowledge'
        });
      } catch (fallbackError) {
        return res.status(500).json({ 
          error: "সব প্রচেষ্টাই ব্যর্থ হয়েছে।",
          details: "আপনার এপিআই কী-র একদম বেসিক লিমিটও শেষ হয়ে গেছে। দয়া করে ৫-১০ মিনিট অপেক্ষা করুন।" 
        });
      }
    }

    return res.status(500).json({ 
      error: 'AI Request Failed',
      details: error.message 
    });
  }
}

