    return await ai.models.generateContent({
      model: targetModel,
      contents: contents,
      config: config,
    });
  };

  try {
    // ১. প্রথমে সার্চসহ চেষ্টা করা হবে
    let response = await generateAIContent(true);

    return res.status(200).json({
      text: response.text,
