const SYSTEM_INSTRUCTION = `
আপনি হলেন "রাজবাড়ী জেলা তথ্য সহায়িকা – AI Chat Assistant"।
আপনার দায়িত্ব ও বৈশিষ্ট্য:
১. রাজবাড়ী জেলা সম্পর্কে সকল তথ্য প্রদান করা।
২. ভাষা: সর্বদা বাংলা ব্যবহার করবেন।
৩. টোন: বিনয়ী ও সম্মানজনক।
৪. ডেভেলপার: Sovrab Roy।
`;

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  sources?: any[];
  mode?: 'live_search' | 'offline_knowledge';
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী জেলা তথ্য সহায়িকা। রাজবাড়ী সম্পর্কে জানতে আপনি আমাকে যেকোনো প্রশ্ন করতে পারেন।' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (retryText?: string) => {
    const userMessage = retryText || input.trim();
    if (!userMessage || isTyping) return;

    if (!retryText) {
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    }

    setIsTyping(true);

    try {
      const chatHistory = messages
        .filter(m => !m.isError)
        .map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }));

      const data = await db.callAI({
        contents: [...chatHistory, { role: 'user', parts: [{ text: userMessage }] }],
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }]
      });

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: data.text,
        sources: data.groundingMetadata?.groundingChunks || [],
        mode: data.mode
      }]);
    } catch (error: any) {
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: `${error.message}`, 
        isError: true 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] animate-slide-up relative">
      <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <Sparkles className="w-5 h-5" />
          </div>
          <div>
            <h3 className="font-black text-slate-800 dark:text-white leading-none">রাজবাড়ী স্মার্ট সাপোর্ট</h3>
            <div className="flex items-center gap-1.5 mt-1">
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter bg-emerald-100 text-emerald-600">
                <ShieldCheck className="w-2.5 h-2.5" />
                System Active
              </div>
            </div>
          </div>
        </div>
        <button onClick={() => setMessages([{ role: 'model', text: 'স্বাগতম! আমি রাজবাড়ী সম্পর্কে আপনাকে কি তথ্য দিয়ে সাহায্য করতে পারি?' }])} className="p-3 text-slate-400 hover:text-rose-500 rounded-xl">
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6 bg-slate-50 dark:bg-slate-950">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800'}`}>
                {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`p-4 rounded-3xl text-sm leading-relaxed whitespace-pre-line shadow-sm border ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none border-indigo-600' 
                  : msg.isError 
                    ? 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-400 border-rose-200 dark:border-rose-900/50'
                    : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 rounded-tl-none border-slate-100 dark:border-slate-800'
                }`}>
                  {msg.isError && <AlertCircle className="w-4 h-4 mb-2 inline-block mr-1" />}
                  {msg.text}

                  {msg.mode === 'offline_knowledge' && (
                    <div className="mt-3 flex items-center gap-2 text-[10px] font-bold text-amber-600 bg-amber-50 dark:bg-amber-900/20 px-3 py-1.5 rounded-xl border border-amber-100 dark:border-amber-900/30">
                      <ZapOff className="w-3.5 h-3.5" /> সার্চ লিমিট শেষ, এআই নলেজ ব্যবহৃত হচ্ছে।
                    </div>
                  )}

                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-4 pt-3 border-t border-slate-200/50 dark:border-slate-700/50">
                      <p className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-2">Verified Sources:</p>
                      <div className="flex flex-wrap gap-2">
                        {msg.sources.map((chunk: any, sidx: number) => (
                          chunk.web && (
                            <a 
                              key={sidx} 
                              href={chunk.web.uri} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="flex items-center gap-1.5 text-[9px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2.5 py-1 rounded-lg border border-indigo-100 dark:border-indigo-800/50"
                            >
                              <Globe className="w-2.5 h-2.5" /> Source {sidx+1}
                            </a>
                          )
                        ))}
                      </div>
                    </div>
                  )}
                </div>
                {msg.isError && (
                  <button onClick={() => handleSend([...messages].reverse().find(m => m.role === 'user')?.text)} className="flex items-center gap-2 text-[10px] font-black text-indigo-600 self-start px-4 py-2 bg-white dark:bg-slate-900 rounded-full border border-slate-100 dark:border-slate-800 shadow-sm">
                    <RefreshCcw className="w-3 h-3" /> পুনরায় চেষ্টা
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-white dark:bg-slate-800 flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100 dark:border-slate-800"><Bot className="w-4 h-4" /></div>
            <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-6 bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-800">
        <div className="flex gap-3 bg-slate-50 dark:bg-slate-900 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-800 focus-within:border-indigo-400 transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="রাজবাড়ী সম্পর্কে জিজ্ঞাসা করুন..." 
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 text-slate-800 dark:text-white"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isTyping}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
              !input.trim() || isTyping ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white shadow-lg'
            }`}
          >
            {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // API_KEY অথবা GEMINI_API_KEY উভয়ই চেক করবে
  const apiKey = process.env.API_KEY || process.env.GEMINI_API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API Key missing',
      details: 'Vercel বা হোস্টিং এনভায়রনমেন্টে API_KEY সেট করা নেই।' 
    });
  }

  const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
  const ai = new GoogleGenAI({ apiKey });

  // প্রাইমারি এবং ফলব্যাক মডেল সেটআপ
  const primaryModel = model || 'gemini-3-flash-preview';
  const fallbackModel = 'gemini-2.5-flash-lite-latest';

  const generateAI = async (useModel, useTools) => {
    return await ai.models.generateContent({
      model: useModel,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন তথ্য সহায়িকা।",
        tools: useTools ? [{ googleSearch: {} }] : [],
        temperature: 0.7,
        responseMimeType: responseMimeType,
        responseSchema: responseSchema
      },
    });
  };

  try {
    // ১. প্রথম চেষ্টা: প্রাইমারি মডেল + গুগল সার্চ
    console.log("Attempting with Google Search...");
    let response = await generateAI(primaryModel, true);

    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_search'
    });

  } catch (error) {
    console.warn('Initial AI Attempt Failed:', error.message);

    // ২. দ্বিতীয় চেষ্টা: ফলব্যাক মডেল + গুগল সার্চ ছাড়া (যেকোনো এরর হলে)
    try {
      console.log("Falling back to standard mode without tools...");
      let fallbackResponse = await generateAI(fallbackModel, false);

      return res.status(200).json({
        text: fallbackResponse.text,
        groundingMetadata: null,
        mode: 'offline_knowledge'
      });
    } catch (fallbackError) {
      console.error('All AI attempts failed:', fallbackError.message);
      return res.status(500).json({ 
        error: "AI Services Unavailable",
        details: fallbackError.message 
      });
    }
  }
}

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock as ClockIcon, 
  Loader2, 
  TrainFront,
  X,
  Radar,
  Sparkles,
  History,
  Info,
  Globe,
  Facebook,
  Navigation,
  RefreshCcw,
  DollarSign,
  TrendingUp,
  TrendingDown,
  ArrowRightCircle
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';
import { RAJBARI_DATA } from '../constants.tsx';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else {
        const items = await db.getCategory(category);
        setData(items);
      }
    } catch (e: any) {
      const items = await db.getCategory(category);
      setData(items);
      setError(e.message || "তথ্য লোড করতে সমস্যা হচ্ছে।");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runMarketAI = async () => {
    try {
      const prompt = `আজকের তারিখ ${new Date().toLocaleDateString('bn-BD')}। রাজবাড়ী জেলার স্থানীয় বাজার থেকে নিত্যপণ্যের দাম বের করুন। JSON Array ফরম্যাটে দিন।`;
      const response = await db.callAI({
        contents: [{ parts: [{ text: prompt }] }],
        systemInstruction: "আপনি রাজবাড়ী জেলার বাজার বিশ্লেষক। শুধুমাত্র JSON Array প্রদান করুন।"
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
    } catch (err: any) {
      setData((RAJBARI_DATA as any).market_price);
      console.error("Market AI Error:", err.message);
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'তথ্য যাচাই করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${currentTime.toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" (নং ${train.id}) ট্রেনটির বর্তমান অবস্থান ফেসবুক লাইভ রিপোর্ট থেকে খুঁজুন। [STATION: স্টেশনের নাম] ফরম্যাটে লিখুন।`;

      const response = await db.callAI({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        systemInstruction: "আপনি রাজবাড়ী রেলওয়ে ট্র্যাকিং অফিসার।",
        model: 'gemini-3-flash-preview' // Lite মডেল অনেক সময় সার্চে ভালো কাজ করে
      });

      const text = response.text || "";
      const stationMatch = text.match(/\[STATION:\s*(.*?)\]/i);

      if (stationMatch && stationMatch[1]) {
        const found = stationMatch[1].trim();
        const routeStations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = routeStations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.95, 
        reason: text.replace(/\[STATION:.*?\]/i, '').trim() || 'লাইভ রিপোর্ট পাওয়া যায়নি।', 
        isAI: true, 
        sources: response.groundingMetadata?.groundingChunks || [] 
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: `এআই সার্ভার এরর: ${e.message}`, 
        isAI: false, 
        sources: [] 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const renderItem = (item: any) => {
    if (category === 'market_price') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600"><DollarSign className="w-7 h-7" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p></div>
        </div>
        <div className="text-right">
          <div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div>
        </div>
      </div>
    );

    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 hover:border-indigo-200 transition-all">
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl"><TrainFront className="w-6 h-6" /></div>
            <div><h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p></div>
          </div>
          <div className="text-right"><p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p></div>
        </div>
      </div>
    );

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl">{item.icon || <Info className="w-6 h-6 text-indigo-500" />}</div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-sm leading-tight">{item.name || item.title || item.org}</h4><p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.mobile || item.time || item.deadline}</p></div>
        </div>
        {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl"><Phone className="w-5 h-5" /></a>}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto overflow-x-hidden">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white uppercase leading-none mb-1">
            {category === 'trains' ? 'রেলওয়ে আপডেট' : category === 'market_price' ? 'বাজারদর (AI)' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">Rajbari Smart Portal</p>
        </div>
        <button onClick={fetchData} className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-indigo-600">
           <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {error && (
        <div className="bg-rose-50 dark:bg-rose-950/20 p-4 rounded-2xl border border-rose-100 dark:border-rose-900/50 mb-6 flex items-center gap-3">
          <AlertCircle className="w-5 h-5 text-rose-500" />
          <p className="text-xs font-bold text-rose-600">{error}</p>
        </div>
      )}

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <Loader2 className="w-14 h-14 animate-spin text-indigo-600" />
          <p className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">তথ্য সংগ্রহ করা হচ্ছে...</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? data.map(renderItem) : <div className="text-center py-20 text-slate-400 font-bold">কোনো তথ্য পাওয়া যায়নি।</div>}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/95 backdrop-blur-xl flex items-end md:items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[3.5rem] overflow-hidden shadow-2xl relative max-h-[92vh] flex flex-col animate-slide-up">
            <button onClick={() => { setSelectedTrain(null); setCurrentStation(null); }} className="absolute top-8 right-8 p-3 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-500 z-50"><X className="w-6 h-6" /></button>
            <div className="p-8 pb-4 overflow-y-auto no-scrollbar">
              <div className="flex items-center gap-4 mb-8">
                <div className="p-4 bg-indigo-600 text-white rounded-[1.8rem] shadow-lg"><TrainFront className="w-8 h-8" /></div>
                <div><h3 className="text-2xl font-black dark:text-white leading-tight">{selectedTrain.name}</h3><p className="text-indigo-500 font-black text-[10px] uppercase tracking-[0.3em]">{selectedTrain.route}</p></div>
              </div>

              <div className="p-6 bg-indigo-50 dark:bg-indigo-950/30 rounded-[2.2rem] border border-indigo-100 dark:border-indigo-900/50 mb-6 relative overflow-hidden">
                 <div className="flex items-center gap-2 mb-4">
