import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // API_KEY অথবা GEMINI_API_KEY অথবা VERCEL_API_KEY সব চেক করবে
  const apiKey = process.env.API_KEY || process.env.GEMINI_API_KEY || process.env.NEXT_PUBLIC_API_KEY;

  if (!apiKey || apiKey.length < 20) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'আপনার হোস্টিং প্যানেলে (Vercel Settings) "API_KEY" নামে ভেরিয়েবলটি সেট করা নেই অথবা কী-টি ভুল।' 
    });
  }

  const { contents, systemInstruction, tools, model } = req.body;
  const ai = new GoogleGenAI({ apiKey });

  // ট্রাই লিস্ট: ১. জেমিনি ৩ + সার্চ, ২. জেমিনি ৩ (সার্চ ছাড়া), ৩. জেমিনি ২.৫ ফ্লাশ (সবচেয়ে স্টেবল)
  const modelsToTry = [
    { name: model || 'gemini-3-flash-preview', useSearch: true },
    { name: model || 'gemini-3-flash-preview', useSearch: false },
    { name: 'gemini-2.5-flash-lite-latest', useSearch: false }
  ];

  for (let i = 0; i < modelsToTry.length; i++) {
    const attempt = modelsToTry[i];
    try {
      console.log(`Attempt ${i + 1}: Using ${attempt.name} (Search: ${attempt.useSearch})`);

      const response = await ai.models.generateContent({
        model: attempt.name,
        contents: contents,
        config: {
          systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন তথ্য সহায়িকা।",
          tools: attempt.useSearch ? [{ googleSearch: {} }] : [],
          temperature: 0.7
        },
      });

      return res.status(200).json({
        text: response.text,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
        mode: attempt.useSearch ? 'live_search' : 'offline_knowledge',
        model_used: attempt.name
      });

    } catch (error) {
      console.error(`Attempt ${i + 1} failed:`, error.message);

      // যদি লাস্ট অ্যাটেম্পটও ফেল করে
      if (i === modelsToTry.length - 1) {
        return res.status(500).json({ 
          error: 'ALL_ATTEMPTS_FAILED',
          details: error.message,
          suggestion: 'আপনার এপিআই কী-টি গুগল এআই স্টুডিও থেকে আবার চেক করুন।' 
        });
      }
      // অন্যথায় লুপ কন্টিনিউ করবে (পরের মডেলে যাবে)
      continue;
    }
  }
}

import 'dotenv/config';
import express from 'express';
import cors from 'cors';
import path from 'path';
import { fileURLToPath } from 'url';
import { GoogleGenAI } from '@google/genai';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();
const port = process.env.PORT || 3001;

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'dist')));

app.post('/api/ai', async (req, res) => {
    const { contents, systemInstruction, model } = req.body;
    const apiKey = process.env.API_KEY || process.env.GEMINI_API_KEY;

    if (!apiKey) {
        return res.status(500).json({ 
            error: "CONFIG_ERROR", 
            details: "আপনার .env ফাইলে API_KEY নেই।" 
        });
    }

    const ai = new GoogleGenAI({ apiKey });

    // Fallback Chain
    const attempts = [
        { m: model || 'gemini-3-flash-preview', s: true },
        { m: model || 'gemini-3-flash-preview', s: false },
        { m: 'gemini-2.5-flash-lite-latest', s: false }
    ];

    for (const attempt of attempts) {
        try {
            const response = await ai.models.generateContent({
                model: attempt.m,
                contents: contents,
                config: {
                    systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন অ্যাসিস্ট্যান্ট।",
                    tools: attempt.s ? [{ googleSearch: {} }] : [],
                    temperature: 0.7
                }
            });

            return res.json({
                text: response.text || "",
                groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
                mode: attempt.s ? 'live_search' : 'offline_knowledge'
            });
        } catch (e) {
            console.warn(`Local attempt with ${attempt.m} failed, trying next...`);
        }
    }

    res.status(500).json({ error: "SERVICE_UNAVAILABLE", details: "সবগুলো এআই মডেল কল ব্যর্থ হয়েছে।" });
});

app.get('*', (req, res) => {
    res.sendFile(path.join(__dirname, 'dist', 'index.html'));
});

