import 'dotenv/config';
import express from 'express';
import cors from 'cors';
import path from 'path';
import { fileURLToPath } from 'url';
import { GoogleGenAI } from '@google/genai';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const app = express();
const port = process.env.PORT || 3001;

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'dist')));

app.post('/api/ai', async (req, res) => {
    // FIX: Extracted responseMimeType and responseSchema from req.body to forward to the GenAI client.
    const { contents, systemInstruction, model, tools, responseMimeType, responseSchema } = req.body;
    const apiKey = process.env.API_KEY || process.env.GEMINI_API_KEY;

    if (!apiKey) {
        return res.status(500).json({ 
            error: "CONFIG_ERROR", 
            details: "আপনার .env ফাইলে API_KEY নেই।" 
        });
    }

    const ai = new GoogleGenAI({ apiKey });

    // Fallback Chain
    const attempts = [
        { m: model || 'gemini-3-flash-preview', s: true },
        { m: model || 'gemini-3-flash-preview', s: false },
        { m: 'gemini-2.5-flash-lite-latest', s: false }
    ];

    for (const attempt of attempts) {
        try {
            const response = await ai.models.generateContent({
                model: attempt.m,
                contents: contents,
                config: {
                    systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন অ্যাসিস্ট্যান্ট।",
                    // FIX: Ensure responseMimeType and responseSchema are passed correctly in the generation config.
                    tools: attempt.s ? [{ googleSearch: {} }] : (tools || []),
                    temperature: 0.7,
                    responseMimeType: responseMimeType,
                    responseSchema: responseSchema
                }
            });

            return res.json({
                text: response.text || "",
                groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
                mode: attempt.s ? 'live_search' : 'offline_knowledge'
            });
        } catch (e) {
            console.warn(`Local attempt with ${attempt.m} failed, trying next...`);
        }
    }

    res.status(500).json({ error: "SERVICE_UNAVAILABLE", details: "সবগুলো এআই মডেল কল ব্যর্থ হয়েছে।" });
});

app.get('*', (req, res) => {
    res.sendFile(path.join(__dirname, 'dist', 'index.html'));
});

app.listen(port, () => {
    console.log(`-------------------------------------------`);
    console.log(`🚀 রাজবাড়ী স্মার্ট পোর্টাল সার্ভার চালু হয়েছে!`);
    console.log(`📍 লোকাল অ্যাড্রেস: http://localhost:${port}`);
