    console.log(`-------------------------------------------`);
});

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // API_KEY অথবা GEMINI_API_KEY অথবা VERCEL_API_KEY সব চেক করবে
  const apiKey = process.env.API_KEY || process.env.GEMINI_API_KEY || process.env.NEXT_PUBLIC_API_KEY;

  if (!apiKey || apiKey.length < 20) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'আপনার হোস্টিং প্যানেলে (Vercel Settings) "API_KEY" নামে ভেরিয়েবলটি সেট করা নেই অথবা কী-টি ভুল।' 
    });
  }

  // FIX: Destructured responseMimeType and responseSchema from req.body to enable structured output support.
  const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
  const ai = new GoogleGenAI({ apiKey });

  // ট্রাই লিস্ট: ১. জেমিনি ৩ + সার্চ, ২. জেমিনি ৩ (সার্চ ছাড়া), ৩. জেমিনি ২.৫ ফ্লাশ (সবচেয়ে স্টেবল)
  const modelsToTry = [
    { name: model || 'gemini-3-flash-preview', useSearch: true },
    { name: model || 'gemini-3-flash-preview', useSearch: false },
    { name: 'gemini-2.5-flash-lite-latest', useSearch: false }
  ];

  for (let i = 0; i < modelsToTry.length; i++) {
    const attempt = modelsToTry[i];
    try {
      console.log(`Attempt ${i + 1}: Using ${attempt.name} (Search: ${attempt.useSearch})`);

      const response = await ai.models.generateContent({
        model: attempt.name,
        contents: contents,
        config: {
          systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন তথ্য সহায়িকা।",
          // FIX: Correctly forward responseMimeType and responseSchema to the GenAI SDK config.
          tools: attempt.useSearch ? [{ googleSearch: {} }] : (tools || []),
          temperature: 0.7,
          responseMimeType: responseMimeType,
          responseSchema: responseSchema
        },
      });

      return res.status(200).json({
        text: response.text,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
        mode: attempt.useSearch ? 'live_search' : 'offline_knowledge',
        model_used: attempt.name
      });

    } catch (error) {
      console.error(`Attempt ${i + 1} failed:`, error.message);

      // যদি লাস্ট অ্যাটেম্পটও ফেল করে
      if (i === modelsToTry.length - 1) {
        return res.status(500).json({ 
          error: 'ALL_ATTEMPTS_FAILED',
          details: error.message,
          suggestion: 'আপনার এপিআই কী-টি গুগল এআই স্টুডিও থেকে আবার চেক করুন।' 
        });
      }
      // অন্যথায় লুপ কন্টিনিউ করবে (পরের মডেলে যাবে)
      continue;
    }
  }
}

import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { return null; }
  },

  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    // এটি চেক করবে যে কোন এন্ডপয়েন্ট কাজ করে
    const endpoints = ['/api/ai', '/api/ai.js', '/api/ai.php'];
    let lastError = '';

    for (const url of endpoints) {
      try {
        const response = await fetch(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: params.contents,
            systemInstruction: params.systemInstruction,
            tools: params.tools,
            model: params.model,
            responseMimeType: params.responseMimeType,
            responseSchema: params.responseSchema
          }),
        });

        const data = await response.json();

        if (response.ok) {
          return {
            text: data.text || "",
            groundingMetadata: data.groundingMetadata || null,
            mode: data.mode || 'standard'
          };
        } else {
          lastError = data.details || data.error || `Error ${response.status}`;
          // যদি ৪০৪ হয়, তবে পরের এন্ডপয়েন্টে যাবে
          if (response.status !== 404) break; 
        }
      } catch (e: any) {
        lastError = e.message;
      }
    }

    throw new Error(lastError || "এআই সার্ভারের সাথে যোগাযোগ করা যাচ্ছে না।");
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

