import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  // শুধুমাত্র POST রিকোয়েস্ট অ্যালাউ করবে
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // API_KEY ভেরিয়েবলটি Vercel ড্যাশবোর্ডে সেট করা থাকতে হবে
  const apiKey = process.env.API_KEY || process.env.GEMINI_API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'Vercel Environment Variables-এ "API_KEY" সেট করা নেই।' 
    });
  }

  const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
  const ai = new GoogleGenAI({ apiKey });

  // Vercel-এর জন্য অপ্টিমাইজড মডেল সিকোয়েন্স
  const models = [
    { name: model || 'gemini-3-flash-preview', search: true },
    { name: model || 'gemini-3-flash-preview', search: false },
    { name: 'gemini-2.5-flash-lite-latest', search: false }
  ];

  for (const entry of models) {
    try {
      const response = await ai.models.generateContent({
        model: entry.name,
        contents: contents,
        config: {
          systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।",
          tools: entry.search ? [{ googleSearch: {} }] : (tools || []),
          temperature: 0.7,
          responseMimeType: responseMimeType,
          responseSchema: responseSchema
        },
      });

      return res.status(200).json({
        text: response.text,
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
        mode: entry.search ? 'live_search' : 'offline_knowledge'
      });

    } catch (error) {
      console.error(`Model ${entry.name} failed:`, error.message);
      // যদি সবগুলো মডেল ট্রাই করা শেষ হয়
      if (entry === models[models.length - 1]) {
        return res.status(500).json({ 
          error: 'GENERATION_FAILED',
          details: error.message 
        });
      }
      continue;
    }
  }
}

import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { return null; }
  },

  /**
   * Vercel Cloud Serverless API Call
   * This calls the function located in /api/ai.js (Vercel backend)
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          contents: params.contents,
          systemInstruction: params.systemInstruction,
          tools: params.tools,
          model: params.model,
          responseMimeType: params.responseMimeType,
          responseSchema: params.responseSchema
        }),
      });

      const data = await response.json();

      if (response.ok) {
        return {
          text: data.text || "",
          groundingMetadata: data.groundingMetadata || null,
          mode: data.mode || 'standard'
        };
      } else {
        throw new Error(data.details || data.error || `Error ${response.status}`);
      }
    } catch (e: any) {
      console.error("Vercel API Connection Error:", e.message);
      throw new Error("এআই সার্ভারের সাথে যোগাযোগ করা যাচ্ছে না। Vercel এ API_KEY সেট করা আছে কি?");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

