interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else {
        const items = await db.getCategory(category);
        setData(items);
      }
    } catch (e: any) {
      const items = await db.getCategory(category);
      setData(items);
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runMarketAI = async () => {
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: "রাজবাড়ী জেলার স্থানীয় বাজারের নিত্যপণ্যের দামের একটি JSON তালিকা দিন।" }] }],
        systemInstruction: "শুধুমাত্র JSON Array প্রদান করুন।",
        model: 'gemini-3-flash-preview'
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
    } catch (err) {
      setData((RAJBARI_DATA as any).market_price);
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'তথ্য যাচাই করা হচ্ছে...', isAI: true, sources: [] });

    try {
      const prompt = `এখন সময় ${new Date().toLocaleTimeString('bn-BD')}। রাজবাড়ী জেলার "${train.name}" (নং ${train.id}) ট্রেনটি বর্তমানে কোথায় আছে? ফেসবুক গ্রুপ বা নিউজ পোর্টাল থেকে সর্বশেষ আপডেট খুঁজুন। আপনার উত্তরে অবশ্যই "[STATION: স্টেশনের নাম]" ট্যাগটি থাকতে হবে। যদি সঠিক স্টেশন না পান তবে সম্ভাব্য অবস্থান বলুন।`;

      const response = await db.callAI({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        systemInstruction: "আপনি একজন দক্ষ রাজবাড়ী রেলওয়ে ট্র্যাকিং অফিসার।",
        model: 'gemini-3-flash-preview'
      });

      const text = response.text || "তথ্য পাওয়া যায়নি।";
      const stationMatch = text.match(/\[STATION:\s*(.*?)\]/i);

      if (stationMatch && stationMatch[1]) {
        const found = stationMatch[1].trim();
        const routeStations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = routeStations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.9, 
