import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { return null; }
  },

  /**
   * Vercel Cloud API Call
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    // Added optional parameters for JSON responses and schema definition
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify(params),
      });

      const data = await response.json();

      if (response.ok) {
        return {
          text: data.text || "",
          groundingMetadata: data.groundingMetadata || null,
          mode: data.mode || 'standard'
        };
      } else {
        throw new Error(data.details || data.error || `Error ${response.status}`);
      }
    } catch (e: any) {
      console.error("Vercel Connection Error:", e.message);
      throw new Error(e.message || "এআই সার্ভার সাড়া দিচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // The API key must be obtained exclusively from process.env.API_KEY.
  if (!process.env.API_KEY) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'Vercel Dashboard এ "API_KEY" সেট করা নেই।' 
    });
  }

  try {
    const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;

    // Always use process.env.API_KEY string directly when initializing the client instance.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Use gemini-3-flash-preview for fast and search-enabled tasks
    const response = await ai.models.generateContent({
      model: model || 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.8,
        // Support response formatting options.
        responseMimeType,
        responseSchema,
      },
    });

    // Access the .text property directly from GenerateContentResponse.
    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_cloud'
    });

  } catch (error) {
    console.error("Vercel AI Error:", error.message);
    return res.status(500).json({ 
      error: 'AI_RESPONSE_ERROR',
      details: error.message 
    });
  }
}

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // API Key check from Environment Variables
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'Vercel ড্যাশবোর্ডে "API_KEY" সেট করা নেই। সেটিংস > এনভায়রনমেন্ট ভেরিয়েবল চেক করুন।' 
    });
  }

  try {
    const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
    const ai = new GoogleGenAI({ apiKey });

    // Using gemini-3-flash-preview for maximum speed and search capability
    const response = await ai.models.generateContent({
      model: model || 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী। গুগল সার্চ ব্যবহার করে সব সময় লেটেস্ট তথ্য দিন।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.7,
        responseMimeType,
        responseSchema,
      },
    });

    // Access the .text property directly
    const textOutput = response.text || "দুঃখিত, কোনো তথ্য খুঁজে পাওয়া যায়নি।";

    return res.status(200).json({
      text: textOutput,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_cloud_v2'
    });

  } catch (error) {
    console.error("Vercel AI Bridge Error:", error.message);

    // Handle specific API errors
    let errorMessage = "এআই সার্ভারে সমস্যা হয়েছে।";
    if (error.message.includes("403")) errorMessage = "এপিআই কী (API Key) অবৈধ বা পারমিশন নেই।";
    if (error.message.includes("429")) errorMessage = "অতিরিক্ত রিকোয়েস্ট পাঠানো হয়েছে। কিছুক্ষণ পর চেষ্টা করুন।";

    return res.status(500).json({ 
      error: 'AI_GATEWAY_ERROR',
      details: errorMessage,
      raw: error.message
    });
  }
}

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Loader2, 
  TrainFront,
  X,
  Sparkles,
  Info,
  Globe,
  Navigation,
  RefreshCcw,
  DollarSign,
  AlertCircle,
  Clock
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';
import { RAJBARI_DATA } from '../constants.tsx';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else {
        const items = await db.getCategory(category);
        setData(items);
      }
    } catch (e: any) {
      const items = await db.getCategory(category);
      setData(items);
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runMarketAI = async () => {
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: "রাজবাড়ী জেলার স্থানীয় বাজারের নিত্যপণ্যের দামের একটি JSON তালিকা দিন। উদাহরণ: [{'name': 'চাল', 'unit': 'কেজি', 'priceRange': '৭০-৮০ টাকা'}]" }] }],
        systemInstruction: "শুধুমাত্র একটি JSON Array প্রদান করুন। অন্য কোনো টেক্সট দেবেন না।",
        model: 'gemini-3-flash-preview'
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
      else throw new Error("JSON parsing failed");
    } catch (err) {
      setData((RAJBARI_DATA as any).market_price);
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'অনলাইনে তথ্য খোঁজা হচ্ছে...', isAI: true, sources: [] });

    try {
      const now = new Date().toLocaleTimeString('bn-BD');
      const prompt = `এখন সময় ${now}। রাজবাড়ী জেলার "${train.name}" (ট্রেন নং ${train.id}) বর্তমানে কোথায় আছে? ফেসবুক গ্রুপ 'Rajbari Rail Club' বা 'Rajbari Helpline' এবং অনলাইন সোর্স থেকে চেক করুন। আপনার উত্তরের শেষে অবশ্যই "[STATION: স্টেশনের নাম]" ট্যাগটি যোগ করবেন। যদি সঠিক স্টেশন না পান তবে "অজানা" লিখুন।`;

      const response = await db.callAI({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        systemInstruction: "আপনি রাজবাড়ী রেলওয়ে ট্র্যাকিং সহকারী। গুগল সার্চ ব্যবহার করে সঠিক তথ্য দিন।",
        model: 'gemini-3-flash-preview'
      });

      const text = response.text || "তথ্য পাওয়া যায়নি।";
      const stationMatch = text.match(/\[STATION:\s*(.*?)\]/i);

      if (stationMatch && stationMatch[1] && !stationMatch[1].includes("অজানা")) {
        const found = stationMatch[1].trim();
        const routeStations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = routeStations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.95, 
        reason: text.replace(/\[STATION:.*?\]/i, '').trim(), 
        isAI: true, 
        sources: response.groundingMetadata?.groundingChunks || [] 
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: "দুঃখিত! এআই সার্ভার কানেকশন এরর: " + (e.message || "Unknown error"), 
        isAI: false, 
        sources: [] 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const renderItem = (item: any) => {
    if (category === 'market_price') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600 shadow-inner"><DollarSign className="w-7 h-7" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p></div>
        </div>
        <div className="text-right"><div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div></div>
      </div>
    );

    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 hover:border-indigo-300 transition-all group overflow-hidden relative">
        <div className="absolute top-0 right-0 w-16 h-16 bg-indigo-500/5 rounded-full blur-2xl -mr-8 -mt-8 transition-all group-hover:scale-150"></div>
        <div className="flex items-start justify-between relative z-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:scale-110 transition-transform"><TrainFront className="w-6 h-6" /></div>
            <div>
              <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-sm font-black text-slate-800 dark:text-white flex items-center gap-2">
              <Clock className="w-3.5 h-3.5 text-indigo-500" />
              {item.departure}
            </p>
          </div>
        </div>
      </div>
    );

    return (
