import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { return null; }
  },

  /**
   * Direct Gemini API Call
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[]; 
    model?: string;
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
        throw new Error("API_KEY is missing in your Vercel Environment Variables.");
      }

      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: params.model || 'gemini-3-flash-preview',
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী। গুগল সার্চ ব্যবহার করে সব সময় সঠিক তথ্য দিন।",
          tools: params.tools || [{ googleSearch: {} }],
          temperature: 0.7,
          responseMimeType: params.responseMimeType,
          responseSchema: params.responseSchema,
        },
      });

      return {
        text: response.text || "",
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
        mode: 'cloud_v3_optimized'
      };
    } catch (e: any) {
      console.error("AI Bridge Error:", e.message);
      throw new Error(e.message || "এআই সার্ভার সাড়া দিচ্ছে না। দয়া করে সেটিংস চেক করুন।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import { RAJBARI_DATA } from './constants.tsx';

// Declare puter for TypeScript
declare const puter: any;

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { return null; }
  },

  /**
   * Puter.js AI Call implementation
   * Replaces direct Gemini SDK to bypass API keys and billing.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    model?: string;
  }) => {
    try {
      if (typeof puter === 'undefined') {
        throw new Error("Puter.js SDK loaded but not initialized correctly.");
      }

      // Convert contents array (history) to a simple string prompt for puter.ai.chat
      // Puter works best with direct strings or formatted chat context
      const historyText = params.contents.map((msg: any) => {
        const roleName = msg.role === 'user' ? 'User' : 'Assistant';
        return `${roleName}: ${msg.parts[0].text}`;
      }).join('\n');

      const fullPrompt = `
        System Instruction: ${params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।"}

        Chat Context:
        ${historyText}

        Answer professionally in Bengali.
      `.trim();

      // Puter.js standard AI call
      const response = await puter.ai.chat(fullPrompt, {
        model: params.model || 'gemini-3-flash-preview'
      });

      return {
        text: response || "",
        groundingMetadata: null, // Puter doesn't expose grounding chunks directly
        mode: 'puter_cloud_v2'
      };
    } catch (e: any) {
      console.error("Puter AI Error:", e.message);
      throw new Error(e.message || "এআই সার্ভার সাড়া দিচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

