import {GoogleGenAI} from "@google/genai";

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { return null; }
  },

  /**
   * Gemini API Call implementation
   * Using the Google GenAI SDK directly as required by the guidelines.
   * This updates the signature to accept 'tools', 'responseMimeType', and 'responseSchema'.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    model?: string;
    tools?: any[];
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      // The API key must be obtained exclusively from the environment variable process.env.API_KEY.
      // Assume this variable is pre-configured, valid, and accessible.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      // Use ai.models.generateContent to query GenAI with both the model name and prompt.
      // Configuration follows the "System Instruction and Other Model Configs" section.
      const response = await ai.models.generateContent({
        model: params.model || 'gemini-3-flash-preview',
        contents: params.contents,
        config: {
          systemInstruction: params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।",
          tools: params.tools,
          responseMimeType: params.responseMimeType,
          responseSchema: params.responseSchema,
          temperature: 0.7,
        },
      });

      // The GenerateContentResponse object features a text property (not a method).
      // Grounding metadata is extracted to support Search Grounding requirements.
      return {
        text: response.text || "",
        groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
        mode: 'client_direct_v3'
      };
    } catch (e: any) {
      console.error("Gemini AI Error:", e.message);

      // Implement robust handling for API errors (e.g., 403, 429)
      let errorMessage = "এআই সার্ভারে সমস্যা হয়েছে।";
      if (e.message?.includes("403")) {
        errorMessage = "এপিআই কী (API Key) অবৈধ বা পারমিশন নেই।";
      } else if (e.message?.includes("429")) {
        errorMessage = "অতিরিক্ত রিকোয়েস্ট পাঠানো হয়েছে। কিছুক্ষণ পর চেষ্টা করুন।";
      }

      throw new Error(errorMessage);
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

