import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Newspaper, ExternalLink, Loader2, Sparkles } from 'lucide-react';
import { db } from '../db';

interface NewsItem {
  title: string;
  source: string;
  time: string;
  link?: string;
}

const NewsSlider: React.FC = () => {
  const [news, setNews] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);

  const fetchNews = async () => {
    setLoading(true);
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: "Fetch the 5 most important latest news headlines for Rajbari District, Bangladesh. Format as JSON array with fields: title, source, time, link." }] }],
        systemInstruction: "You are a local news aggregator for Rajbari. Only return a valid JSON array of objects. Use Bengali for titles.",
        model: 'gemini-3-flash-preview'
      });
      const parsed = db.extractJSON(response.text);
      if (parsed && Array.isArray(parsed)) {
        setNews(parsed);
      } else {
        throw new Error("Invalid format");
      }
    } catch (e) {
      setNews([
        { title: "রাজবাড়ীতে ট্রেন দুর্ঘটনার পর উদ্ধার কাজ সম্পন্ন", source: "রাজবাড়ী টাইমস", time: "২ ঘণ্টা আগে" },
        { title: "পদ্মার পানি বৃদ্ধি, নিম্নাঞ্চল প্লাবিত হওয়ার শঙ্কা", source: "প্রথম আলো", time: "৫ ঘণ্টা আগে" },
        { title: "রাজবাড়ী সদর হাসপাতালে নতুন ডায়ালাইসিস ইউনিট উদ্বোধন", source: "বাংলা নিউজ", time: "১ দিন আগে" }
      ]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchNews();
  }, []);

  useEffect(() => {
    if (news.length > 0) {
      const timer = setInterval(() => {
        setCurrentIndex((prev) => (prev + 1) % news.length);
      }, 5000);
      return () => clearInterval(timer);
    }
  }, [news]);

  const nextSlide = () => setCurrentIndex((prev) => (prev + 1) % news.length);
  const prevSlide = () => setCurrentIndex((prev) => (prev === 0 ? news.length - 1 : prev - 1));

  if (loading) {
    return (
