      `;

      const response = await db.callAI({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        systemInstruction: "আপনি রাজবাড়ী রেলওয়ে ট্র্যাকিং সহকারী। লেটেস্ট ফেসবুক পোস্ট ও ওয়েব নিউজ থেকে তথ্য সংগ্রহ করাই আপনার কাজ।",
