        const found = stationMatch[1].trim();
        setCurrentStation(found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.95, 
        reason: text.replace(/\[STATION:.*?\]/i, '').trim(), 
        isAI: true, 
        sources: [] 
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: "দুঃখিত! নেটওয়ার্ক সমস্যা বা সোর্স পাওয়া যায়নি।", 
        isAI: false, 
        sources: [] 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

