                  <div className="text-sm font-medium text-slate-700 dark:text-slate-200 leading-relaxed italic">
                    "{aiInference.reason}"
                  </div>

                  {isInferring && (
                    <div className="mt-4 flex items-center gap-2 text-indigo-500 font-black text-[10px] animate-pulse">
                       <Loader2 className="w-3 h-3 animate-spin" /> লেটেস্ট আপডেট খোঁজা হচ্ছে...
