                 </div>
               </div>
            </div>

            {/* Bottom Status Button - Exactly like User Screenshot */}
            <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-slate-50 dark:from-slate-900 via-slate-50/90 dark:via-slate-900/90 to-transparent">
