    } catch (e: any) {
      console.error("Puter AI Error:", e.message);
      throw new Error("এআই সার্ভার সাড়া দিচ্ছে না। ইন্টারনেটে ট্রেন ট্র্যাকিং তথ্য পাওয়া যাচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import { RAJBARI_DATA } from './constants.tsx';

// Declare puter for TypeScript environment
declare const puter: any;

export const db = {
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      // Find JSON block even if model wraps it in Markdown code blocks
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * AI Call implementation
   * Using internal /api/ai bridge to interact with Google GenAI SDK.
   * This fixes type errors when passing tools, responseMimeType or responseSchema.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    model?: string;
    tools?: any[];
    responseMimeType?: string;
    responseSchema?: any;
  }) => {
    try {
      // Attempt to call the internal Vercel API bridge (api/ai.js)
      const response = await fetch('/api/ai', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(params),
      });

      if (response.ok) {
        return await response.json();
      }

      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.details || 'এআই সার্ভার সাড়া দিচ্ছে না।');

    } catch (e: any) {
      console.error("AI Bridge Error, falling back to Puter:", e.message);

      // Fallback for Puter.js if the API bridge fails
      if (typeof puter !== 'undefined') {
        try {
          const historyText = Array.isArray(params.contents) ? params.contents.map((msg: any) => {
            const roleName = msg.role === 'user' ? 'User' : 'Assistant';
            const content = msg.parts ? msg.parts[0].text : (msg.text || '');
            return `${roleName}: ${content}`;
          }).join('\n') : params.contents;

          const fullPrompt = `
            ${params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।"}

            Chat Context:
            ${historyText}
          `.trim();

          const response = await puter.ai.chat(fullPrompt);

          return {
            text: typeof response === 'string' ? response : (response?.message?.content || ""),
            groundingMetadata: null,
            mode: 'puter_fallback'
          };
        } catch (pe) {
          throw new Error("এআই সার্ভার সাড়া দিচ্ছে না। ইন্টারনেটে ট্রেন ট্র্যাকিং তথ্য পাওয়া যাচ্ছে না।");
        }
      }
      throw e;
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};
